import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _arbalest_cloak = {title: "Arbalest Cloak", jsx: <><h2 id="magic-wondrous-arbalest_cloak-arbalest-cloak">Arbalest Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_122_into_the_shattered_continent">Pathfinder #122: Into the Shattered Continent pg. 73</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 8 lbs.</p>
<p>Images of ballistae ornament this metallic cloak, which fits easily over armor and other bulky clothing. The wearer can activate this cloak as a swift action, causing the garment to splay outward for 1 round, its jagged hem protruding around the wearer in stiff, sharp points. While the cloak is active, the wearer counts as wearing <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-armorenh/armor_spikes">armor spikes</Link> with which she is proficient, and she can walk on air (as though using the <em>air walk</em> spell). If she's riding a mount, the <em>air walk</em> effect instead affects the mount while the cloak is active, and the mount can move with the item's help even if it's not specially trained to move with the aid of <em>air walk.</em> If the wearer (or her mount) isn't standing on a solid surface by the end of the round, she immediately falls, taking any applicable falling damage.</p>
<p>In addition, on her first successful <Link to="/rule/charge">charge</Link> attack during the round the cloak is active, the wearer deals an additional 1d6 points of piercing damage (1d4 if she is Small), plus another 1d6 (or 1d4 if she is Small) for every 20 feet the wearer traveled in a straight line during the charge (maximum 3d6).</p>
<p>This cloak can be activated up to three times per day, but not more often than once per minute.</p>
<h3 id="magic-wondrous-arbalest_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_walk">air walk</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _arms_of_the_marilith = {title: "Arms of the Marilith", jsx: <><h2 id="magic-wondrous-arms_of_the_marilith-arms-of-the-marilith">Arms of the Marilith</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This leather harness has four clockwork arms attached to it. When it's worn, the arms are positioned behind the wearer's shoulders, with one pair slightly higher than the wearer's and the other set slightly lower, and they spring to life and move under the wearer's control. The arms lack the agility to aid in casting spells, crafting, picking locks, or completing any other fine motor skill, and can't use items placed in their hands. However, each arm's hand can hold any item the wearer could hold in one hand, allowing the wearer to have up to six total pieces of equipment ready for use at once. Once per round as a free action, the wearer can switch which items are held by which hands. Weapons wielded by the arms can't be used for most attacks but can take advantage of a foe's distraction or lowered guard - each clockwork arm wielding a weapon can make one attack of opportunity per round, and all such attacks are treated as <Link to="/rule/off_hand">off-hand</Link> attacks.</p>
<h3 id="magic-wondrous-arms_of_the_marilith-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _aspergillum_cloak = {title: "Aspergillum Cloak", jsx: <><h2 id="magic-wondrous-aspergillum_cloak-aspergillum-cloak">Aspergillum Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 22</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This drab brown, hooded cloak acts as a <Link to="/magic-wondrous/cloak_of_resistance_1">cloak of resistance +1</Link> but also quickly absorbs any liquids poured onto it, drying in moments. Three times per day, the wearer can pour a vial of <Link to="/eq-weapon/holy_water">holy water</Link> onto the interior lining of an aspergillum cloak, causing its outer surface to glisten and drip. The holy water cannot be recovered once absorbed. For 7 minutes, the garment is soaked in holy water, dealing 2d4 points of damage to any undead or evil outsider that strikes the wearer with an unarmed strike or a natural weapon. An aspergillum cloak can also absorb unholy water instead, dealing damage to good outsiders instead. An aspergillum cloak gains no special abilities from absorbing any other liquid.</p>
<h3 id="magic-wondrous-aspergillum_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless_water">bless water</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _bear_pelt_of_the_bonebreaker = {title: "Bear Pelt of the Bonebreaker", jsx: <><h2 id="magic-wondrous-bear_pelt_of_the_bonebreaker-bear-pelt-of-the-bonebreaker">Bear Pelt of the Bonebreaker</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 260</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 54</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This large bearskin cloak is almost too big for a human to wear comfortably. The wearer gains a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. Once per day, the wearer can use <em>bless;</em> using this ability causes the hair on the cloak to bristle menacingly.</p>
<p>If the stone giant deity <Link to="/faith/urazra">Urazra</Link> is the wearer's patron, the wearer can use <em>beast shape II</em> once per day to transform into a black or brown bear for up to 7 minutes. Some champions of Urazra claim to have more powerful pelts that allow them to take the form of polar bears or even dire bears.</p>
<h3 id="magic-wondrous-bear_pelt_of_the_bonebreaker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/bless">bless</Link>, creator must have 5 ranks in Intimidate; <strong>Cost</strong> 1,650 gp</p>
</>};
const _caparison_of_resistance = {title: "Caparison of Resistance", jsx: <><h2 id="magic-wondrous-caparison_of_resistance-caparison-of-resistance">Caparison of Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 16</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,700 gp (+1 bonus), 10,800 gp (+2 bonus), 24,300 gp (+3 bonus), 43,200 gp (+4 bonus), 67,500 gp (+5 bonus); <strong>Weight</strong> 4 lbs.</p>
<p>This garment is intended for a horse or similar quadruped, but it can change size and shape to fit any four-legged creature ranging from Small to Huge in size. When worn, a caparison of resistance offers the wearer magic protection in the form of a +1 to +5 resistance bonus on all saving throws (Fortitude, Reflex, and Will). This bonus on saving throws also applies to a single rider who is mounted on the creature (in the case of multiple riders, the resistance bonus is not shared at all and applies only to the mount).</p>
<h3 id="magic-wondrous-caparison_of_resistance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resistance">resistance</Link>, creator's caster level must be at least three times the cloak's bonus; <strong>Cost</strong> 1,350 gp (+1 bonus), 5,400 gp (+2 bonus), 12,150 gp (+3 bonus), 21,600 gp (+4 bonus), 33,750 gp (+5 bonus)</p>
</>};
const _cape_of_anchoring = {title: "Cape of Anchoring", jsx: <><h2 id="magic-wondrous-cape_of_anchoring-cape-of-anchoring">Cape of Anchoring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 344</Link></p>
<p><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Weight</strong> 1 lb.</p>
<p>This bright red and gold cape appears to be a <em>cape of the mountebank.</em> Once worn, however, it affects its wearer as if subject to a <Link to="/spell/dimensional_anchor">dimensional anchor</Link> spell. The cape can only be removed after its wearer is subject to a <Link to="/spell/remove_curse">remove curse</Link> spell or similar effect.</p>
<h3 id="magic-wondrous-cape_of_anchoring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/cape_of_the_mountebank">cape of the mountebank</Link>; <strong>Cost</strong> -</p>
</>};
const _cape_of_daring_deeds = {title: "Cape of Daring Deeds", jsx: <><h2 id="magic-wondrous-cape_of_daring_deeds-cape-of-daring-deeds">Cape of Daring Deeds</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 228</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The wearer can spend a full-round action concentrating to change the color of this short, silken cape to match any attire or mood. When using the <Link to="/swashdeed/derring_do">derring-do</Link> 1st-level swashbuckler deed, the wearer adds an additional die when rolling either a natural 5 or 6 rather than just a natural 6. Additionally, the cape grants a +2 resistance bonus on saving throws. This bonus increases to +4 for 1 round each time the wearer uses the charmed life <Link to="/class/swashbuckler">swashbuckler</Link> class feature.</p>
<h3 id="magic-wondrous-cape_of_daring_deeds-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _cape_of_effulgent_escape = {title: "Cape of Effulgent Escape", jsx: <><h2 id="magic-wondrous-cape_of_effulgent_escape-cape-of-effulgent-escape">Cape of Effulgent Escape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link><br/><strong>Aura</strong> faint evocation and illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This shining white cloak is trimmed with golden sunbursts and continuously radiates light (as per the <Link to="/spell/light">light</Link> spell, but only in a 10-foot radius). Twice per day, the wearer can command the cape to erupt in a burst of light, <Link to="/misc/blind">blinding</Link> all creatures other than the wearer within 20 feet for 1d4 rounds (Reflex DC 14 negates). After triggering this burst, the wearer becomes invisible (as the <em>invisibility</em> spell, with a duration of 1 minute) and the cape's light is extinguished as long as the wearer is invisible.</p>
<h3 id="magic-wondrous-cape_of_effulgent_escape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _cape_of_feinting = {title: "Cape of Feinting", jsx: <><h2 id="magic-wondrous-cape_of_feinting-cape-of-feinting">Cape of Feinting</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 228</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 8th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This hooded cape is crafted from fine fabric with colorful embroidery and elegant weasel-fur trim. Three times per day, the wearer can spend a standard action to purposely miss an opponent, performing a dramatic feint that causes that opponent to lose its Dexterity bonus to AC until the wearer's next turn. If a <Link to="/class/swashbuckler">swashbuckler</Link> wearing the cloak of feinting performs the <Link to="/swashdeed/superior_feint">superior feint</Link> deed or uses this cape's ability, the opponent is also <Link to="/misc/dazed">dazed</Link> until the start of the swashbuckler's next turn if the foe fails a DC 13 Will save.</p>
<h3 id="magic-wondrous-cape_of_feinting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daze">daze</Link>, creator must be able to perform the superior feint deed; <strong>Cost</strong> 7,000 gp</p>
</>};
const _cape_of_free_will_1_2w = {title: "Cape of Free Will (+1, +2W)", jsx: <><h2 id="magic-wondrous-cape_of_free_will_1_2w-cape-of-free-will">Cape of Free Will</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 148</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,500 gp (+1, +2W), 6,000 gp (+2, +3W), 13,500 gp (+3, +4W), 24,000 gp (+4, +5W), 37,500 gp (+5/+6 Will); <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this brightly colored patchwork cape gains a bonus on all saving throws, as with a <Link to="/magic-wondrous/cloak_of_resistance">cloak of resistance</Link>, but the resistance bonus on Will saves is one greater. Furthermore, if the wearer fails a Will saving throw, he can expend one use of mythic power as an immediate action to reroll that saving throw. If the wearer fails the saving throw on the reroll, he can't use this ability again for 24 hours.</p>
<h3 id="magic-wondrous-cape_of_free_will_1_2w-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/resistance">resistance</Link>, the creator must have the mythic saves ability; <strong>Cost</strong> 750 gp (+1, +2W), 3,000 gp (+2, +3W), 6,750 gp (+3, +4W), 12,000 gp (+4, +5W), 18,750 gp (+5/+6 Will)</p>
</>};
const _cape_of_the_mountebank = {title: "Cape of the Mountebank", jsx: <><h2 id="magic-wondrous-cape_of_the_mountebank-cape-of-the-mountebank">Cape of the Mountebank</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 505</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>Once per day on command, this bright red and gold cape allows the wearer to use the magic of the <em>dimension door</em> spell. When he disappears, he leaves behind a cloud of harmless gray smoke, appearing in a similar dramatic fashion at his destination.</p>
<h3 id="magic-wondrous-cape_of_the_mountebank-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _catching_cape = {title: "Catching Cape", jsx: <><h2 id="magic-wondrous-catching_cape-catching-cape">Catching Cape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 302</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 200 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This silvery cape furls and ripples like a flag with every step its owner takes. As a swift action, the wearer can order the cape to transform into a faint sphere of force that surrounds him on all sides. The field grants the wearer <Link to="/rule/concealment">concealment</Link> (20% miss chance) against ranged attacks and lasts for 1 minute or until the wearer is missed by a ranged attack due to the power of the cloak, whichever comes first. When the field is used, all magic is lost from the cloak, leaving only a mundane silvery garment.</p>
<h3 id="magic-wondrous-catching_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 100 gp</p>
</>};
const _charlatans_cape = {title: "Charlatan's Cape", jsx: <><h2 id="magic-wondrous-charlatans_cape-charlatans-cape">Charlatan's Cape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link><br/><strong>Aura</strong> strong evocation and illusion; <strong>CL</strong> 13th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 45,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This garish cape of red velvet is embroidered with gold-threaded patterns, typically in shapes of sinisterly masked harlequins or other imagery of sinister revelry. The cape acts like a <Link to="/magic-wondrous/cape_of_the_mountebank">cape of the mountebank</Link>, but its <em>dimension door</em> power can be used three times per day. Furthermore, once per day the wearer of the cape can use <em>ethereal jaunt,</em> as per the spell.</p>
<h3 id="magic-wondrous-charlatans_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Cost</strong> 22,500 gp</p>
</>};
const _cloak_of_arachnida = {title: "Cloak of Arachnida", jsx: <><h2 id="magic-wondrous-cloak_of_arachnida-cloak-of-arachnida">Cloak of Arachnida</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 506</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This red and violet silk garment, delicately embroidered with a barely perceptible web-like pattern, gives the wearer the ability to climb as if a <em>spider climb</em> spell had been placed upon her. In addition, the cloak grants her immunity to entrapment by <em>web</em> spells or webs of any sort; she can move in webs at half her normal speed. Once per day, the wearer of this cloak can cast <em>web.</em> She also gains a +2 luck bonus on all Fortitude saves against poison from spiders.</p>
<h3 id="magic-wondrous-cloak_of_arachnida-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spider_climb">spider climb</Link>, <Link to="/spell/web">web</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _cloak_of_blood_alarm_ratfolk = {title: "Cloak of Blood Alarm (Ratfolk)", jsx: <><h2 id="magic-wondrous-cloak_of_blood_alarm_ratfolk-cloak-of-blood-alarm-ratfolk">Cloak of Blood Alarm (Ratfolk)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 230</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This leather cloak looks tattered and stained no matter how carefully it is cleaned and repaired. Once per day, when a <Link to="/race/ratfolk">ratfolk</Link> wearer bleeds upon the cloak (generally when he takes hit point damage), the cloak mentally alerts the wearer's nearest ratfolk ally within 10 miles, telling her the approximate distance and direction to the wearer. It also alerts the wearer to the approximate distance and direction of that ally.</p>
<h3 id="magic-wondrous-cloak_of_blood_alarm_ratfolk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/locate_creature">locate creature</Link>, <Link to="/spell/status">status</Link>, creator must be a ratfolk; <strong>Cost</strong> 1,600 gp</p>
</>};
const _cloak_of_daggers = {title: "Cloak of Daggers", jsx: <><h2 id="magic-wondrous-cloak_of_daggers-cloak-of-daggers">Cloak of Daggers</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 14</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This heavy black cloak is trimmed with silver brocade and jingles ever so slightly when disturbed. The wearer of a cloak of daggers can draw <Link to="/eq-weapon/dagger">daggers</Link> as a free action as though she possessed the <Link to="/feat/quick_draw">Quick Draw</Link> feat; if she already has the Quick Draw feat, drawing a single hidden dagger becomes a free action. Once per day, the wearer can perform a cartwheel as a standard action at any point during a move action, creating a 15-foot cone of daggers that deals an amount of piercing damage equal to the wearer's <Link to="/ability/sneak_attack">sneak attack</Link> damage (minimum 1d6). A successful Reflex save (DC = 10 + the number of the wearer's sneak attack dice + the wearer's Intelligence modifier) halves the damage. The daggers disappear immediately.</p>
<h3 id="magic-wondrous-cloak_of_daggers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Quick Draw, <Link to="/spell/wreath_of_blades">wreath of blades</Link>, creator must possess the sneak attack class ability; <strong>Cost</strong> 9,000 gp</p>
</>};
const _cloak_of_disarming = {title: "Cloak of Disarming", jsx: <><h2 id="magic-wondrous-cloak_of_disarming-cloak-of-disarming">Cloak of Disarming</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 228</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloak is well crafted and stylish. As a swift action, the wearer can direct the cloak to attempt a combat maneuver check to <Link to="/rule/disarm">disarm</Link> a creature within 5 feet, using the wearer's CMB. This disarm combat maneuver does not provoke attacks of opportunity. If the attempt fails, the wearer doesn't risk losing the cloak. The wearer can spend 1 panache point before making the disarm attempt to gain a +5 competence bonus on the combat maneuver check.</p>
<h3 id="magic-wondrous-cloak_of_disarming-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/improved_disarm">Improved Disarm</Link>, <Link to="/spell/pilfering_hand">pilfering hand</Link>, creator must be a panache user; <strong>Cost</strong> 17,500 gp</p>
</>};
const _cloak_of_displacement_minor = {title: "Cloak of Displacement (Minor)", jsx: <><h2 id="magic-wondrous-cloak_of_displacement_minor-cloak-of-displacement">Cloak of Displacement</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 262</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 506-7</Link><br/><strong>Aura</strong> faint (minor) or moderate (major) illusion; <strong>CL</strong> 3rd (minor), 7th (major)<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 24,000 gp (minor), 50,000 gp (major); <strong>Weight</strong> 1 lb.</p>
<p><strong className="hl">Minor:</strong> This item appears to be a normal cloak, with a pattern very similar to a <Link to="/magic-wondrous/major_cloak_of_displacement">major cloak of displacement</Link> nocturnal designs, but when worn its magical properties distort and warp light waves. This displacement works similar to the <em>blur</em> spell, granting a 20% miss chance on attacks against the wearer. It functions continually.</p>
<p><strong className="hl">Major:</strong> Embroidered with images of falling stars and pale moons, this item appears to be a normal cloak, but on command its magical properties distort and warp light waves. This displacement works just like the <em>displacement</em> spell and lasts for a total of 15 rounds per day, which the wearer can divide up as she sees fit.</p>
<h3 id="magic-wondrous-cloak_of_displacement_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extend_spell">Extend Spell</Link> (major only), <Link to="/spell/blur">blur</Link> (minor only), <Link to="/spell/displacement">displacement</Link> (major only) ; <strong>Cost</strong> 12,000 gp (minor), 25,000 gp (major)</p>
</>};
const _cloak_of_elvenkind = {title: "Cloak of Elvenkind", jsx: <><h2 id="magic-wondrous-cloak_of_elvenkind-cloak-of-elvenkind">Cloak of Elvenkind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 263</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 507</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These cloaks of famed elven design are enhanced to reflect the wearer's surroundings, aiding him in blending in with any terrain. When this plain gray cloak is worn with the hood drawn up around the head, the wearer gains a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks.</p>
<h3 id="magic-wondrous-cloak_of_elvenkind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, creator must be an elf; <strong>Cost</strong> 1,250 gp</p>
</>};
const _cloak_of_eternal_mist = {title: "Cloak of Eternal Mist", jsx: <><h2 id="magic-wondrous-cloak_of_eternal_mist-cloak-of-eternal-mist">Cloak of Eternal Mist</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 20</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>Cool, damp mist constantly emanates from beneath this billowing, floor-length cloak. The cloak's wearer gains a +4 bonus on <Link to="/skill/stealth">Stealth</Link> checks in fog or mist. Furthermore, the cloak's wearer is treated as being submerged in water for purposes of racial water dependency. If the cloak's wearer does not move in a given round (and is not otherwise moved, such as when the wearer is on a moving ship or wagon or subject to a successful <Link to="/rule/bull_rush">bull rush</Link> combat maneuver), she gains <Link to="/rule/concealment">concealment</Link> at the end of her turn. The concealment lasts until the wearer moves from her position.</p>
<h3 id="magic-wondrous-cloak_of_eternal_mist-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_water">create water</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Cost</strong> 1,800 gp</p>
</>};
const _cloak_of_etherealness = {title: "Cloak of Etherealness", jsx: <><h2 id="magic-wondrous-cloak_of_etherealness-cloak-of-etherealness">Cloak of Etherealness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 263</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 507</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 55,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This silvery gray cloak seems to absorb light rather than be illuminated by it. On command, the cloak makes its wearer ethereal (as the <em>ethereal jaunt</em> spell). The effect is <Link to="/misc/dismissible">dismissible</Link>. The cloak works for a total of up to 10 minutes per day. This duration need not be continuous, but it must be used in 1 minute increments.</p>
<h3 id="magic-wondrous-cloak_of_etherealness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Cost</strong> 27,500 gp</p>
</>};
const _cloak_of_fangs = {title: "Cloak of Fangs", jsx: <><h2 id="magic-wondrous-cloak_of_fangs-cloak-of-fangs">Cloak of Fangs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 263</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 119</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>Wearing this animal-hair cloak grants a +1 resistance bonus on saving throws. Furthermore, the wearer can force its teeth to grow rapidly up to five times per day as a swift action. The oversized teeth last for 1 round, during which time the wearer can make a bite attack. Treat this attack as a primary <Link to="/rule/natural_attack">natural attack</Link> that deals 1d6 points of damage (or 1d4 if the wearer is Small). If the wearer already has a bite attack, the damage of that bite attack increases <Link to="/misc/by_one_step">by one step</Link>.</p>
<h3 id="magic-wondrous-cloak_of_fangs-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _cloak_of_fiery_vanishing = {title: "Cloak of Fiery Vanishing", jsx: <><h2 id="magic-wondrous-cloak_of_fiery_vanishing-cloak-of-fiery-vanishing">Cloak of Fiery Vanishing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 130</Link><br/><strong>Aura</strong> faint abjuration and illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thick leather cloak is charred and blackened around the edges and smells faintly of soot. Once per day, when subject to an effect that deals fire damage, the wearer can spend an immediate action while obscured by the flames to become invisible, leaving behind an illusory pile of ashes and bones, as if he had been slain by the fire effect. The wearer's <em>invisibility</em> and his illusory remains last for 5 rounds or until the wearer attacks any creature. Creatures that study or interact with the ashes can make a DC 11 Will save to disbelieve the illusion, though this does not end the <em>invisibility</em> effect.</p>
<h3 id="magic-wondrous-cloak_of_fiery_vanishing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/silent_image">silent image</Link>; <strong>Cost</strong> 1,300 gp</p>
</>};
const _cloak_of_flash_and_shadow = {title: "Cloak of Flash and Shadow", jsx: <><h2 id="magic-wondrous-cloak_of_flash_and_shadow-cloak-of-flash-and-shadow">Cloak of Flash and Shadow</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 20</Link><br/><strong>Aura</strong> minor illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> cloak; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Designed to meet the dual needs of the Chelish elite - glamour and subtlety - the cloak of flash and shadow is a magic reversible cloak. When worn one way, the cloak shimmers with heavy gold and silver embroidery against richly colored silk, and grants you a +2 enhancement bonus to Charisma.</p>
<p>When worn inside-out, the matte-black lining seems to absorb light, cloaking you in shadow and giving you a +2 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. In this configuration you can cast <em>blur</em> three times per day.</p>
<p>Reversing the cloak's position is a standard action and requires at least one free hand.</p>
<h3 id="magic-wondrous-cloak_of_flash_and_shadow-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blur">blur</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _cloak_of_good_fortune = {title: "Cloak of Good Fortune", jsx: <><h2 id="magic-wondrous-cloak_of_good_fortune-cloak-of-good-fortune">Cloak of Good Fortune</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 28</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This elegant cloak has simple prayers to <Link to="/family/kami">kami</Link> stitched into its lining. The wearer gains a +1 luck bonus on attack rolls, and once per day, the wearer can spend 10 minutes reciting prayers from the cloak's lining to pose a single question to a nearby spirit, as per <em>commune.</em></p>
<h3 id="magic-wondrous-cloak_of_good_fortune-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/commune">commune</Link>, <Link to="/spell/divine_favor">divine favor</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _cloak_of_heavenly_fire = {title: "Cloak of Heavenly Fire", jsx: <><h2 id="magic-wondrous-cloak_of_heavenly_fire-cloak-of-heavenly-fire">Cloak of Heavenly Fire</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 16</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulder; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This white silk cloak shimmers with divine energy. Once per day as an immediate action, the wearer of a cloak of heavenly fire can cause it to flash with flames as another creature touches the wearer or strikes the wearer with a melee attack. These flames deal 1d8+5 points of fire damage to the creature that touched the wearer. If the creature subjected to this damage is evil, it takes an additional 1d8+5 points of damage as the fire glows with golden light - this additional damage is divine in nature and not subject to energy resistance or immunity. A target that succeeds at a DC 15 Reflex save takes half the total damage. Once per day as a standard action, the wearer of a cloak of heavenly fire can also use the magic to cure wounds, restoring 2d8+5 hit points to a touched creature.</p>
<h3 id="magic-wondrous-cloak_of_heavenly_fire-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/fire_shield">fire shield</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _cloak_of_human_guise = {title: "Cloak of Human Guise", jsx: <><h2 id="magic-wondrous-cloak_of_human_guise-cloak-of-human-guise">Cloak of Human Guise</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 58</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 900 gp; <strong>Weight</strong> 1 lb.</p>
<p>This plain cloak only has any effect when worn by a member of a half-human race, such as a <Link to="/race/half_orc">half-orc</Link> or <Link to="/race/half_elf">half-elf</Link>. It alters the wearer's appearance similarly to a <Link to="/magic-wondrous/hat_of_disguise">hat of disguise</Link>, but only to the extent that it conceals or alters the wearer's non-human physical traits so the creature appears fully human. Any feature that is plausibly human remains. For example, a half-orc wearing the cloak loses his green or gray skin color and pointed ears, has no visible tusks, and is otherwise completely able to pass as a human version of his normal self. Likewise, a half-elf wearing the cloak has round ears, human-like eyes, and no other traits indicating elven ancestry. The wearer has no control over the specific guise, and those familiar with his normal appearance can recognize him in his human guise.</p>
<h3 id="magic-wondrous-cloak_of_human_guise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _cloak_of_immolation = {title: "Cloak of Immolation", jsx: <><h2 id="magic-wondrous-cloak_of_immolation-cloak-of-immolation">Cloak of Immolation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 344</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> strong evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> shoulders; <strong>Weight</strong> 1 lb.</p>
<p>This cloak appears to be a finely made garment that radiates protective magic. The cloak can be handled or examined without harm, but when it is put on, it immediately bursts into flames that burn continuously but do not harm the cloak, only its wearer. The cloak deals 1d6 points of fire damage each round and cannot be removed unless the curse is broken. Sufficient amounts of water or other smothering materials can douse the flames temporarily, but the cloak reignites when exposed to air again. Spells like <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/protection_from_energy">protection from energy</Link>, and similar effects can protect the wearer against the cloak's flames while they last.</p>
<h3 id="magic-wondrous-cloak_of_immolation-construction">Construction</h3>
<p><strong>Requirements</strong> any cloak; <strong>Cost</strong> -</p>
</>};
const _cloak_of_moral_refraction = {title: "Cloak of Moral Refraction", jsx: <><h2 id="magic-wondrous-cloak_of_moral_refraction-cloak-of-moral-refraction">Cloak of Moral Refraction</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 28</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 54,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>The cloak of moral refraction has long been a tool of the <Link to="/pclass/riftwarden">riftwardens</Link> - mystics who charge themselves with maintaining cosmic balance and closing extraplanar portals throughout the multiverse. The shimmering fabric of this light silver-and-red cloak never dirties or wrinkles, and when laid out flat, the cloak reflects light nearly as well as a mirror.</p>
<p>A fully charged cloak of moral refraction has 3 charges; charges used are automatically renewed at a rate of 1 charge per day at dawn. The wearer may use the cloak to expend these charges and create the following effects.</p>
<ul>
<li><strong>1 charge:</strong> Dispel an ongoing spell with an alignment descriptor, as the third function of <Link to="/spell/dispel_chaos">dispel chaos/evil/good/law</Link>.</li>
<li><strong>2 charges:</strong> <Link to="/rule/ready">Ready</Link> an action to <Link to="/rule/counterspells">counter</Link> a spell or spell-like ability with an alignment descriptor. The effect is automatically countered, and no caster level check is required. The charges are expended only after countering a spell or spell-like ability. If you ready this action but it is not triggered, the charges are not expended.</li>
<li><strong>3 charges:</strong> As an immediate action, counter a spell or spell-like ability cast by an outsider with an alignment subtype. The effect is automatically countered, and no caster level check is required. In addition, the outsider must succeed at a DC 20 Will save or be banished back to its home plane, as <em>banishment.</em> An outsider with more than 26 Hit Dice is unaffected by the banishment effect.</li>
</ul>
<h3 id="magic-wondrous-cloak_of_moral_refraction-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/banishment">banishment</Link>, <Link to="/spell/dispel_chaos">dispel chaos</Link>, <Link to="/spell/dispel_evil">evil</Link>, <Link to="/spell/dispel_good">good</Link>, and <Link to="/spell/dispel_law">law</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, creator must be neutral; <strong>Cost</strong> 27,100 gp</p>
</>};
const _cloak_of_quick_reflexes_1_2r = {title: "Cloak of Quick Reflexes (+1, +2R)", jsx: <><h2 id="magic-wondrous-cloak_of_quick_reflexes_1_2r-cloak-of-quick-reflexes">Cloak of Quick Reflexes</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 149</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,500 gp (+1, +2R), 6,000 gp (+2, +3R), 13,500 gp (+3, +4R), 24,000 gp (+4, +5R), 37,500 gp (+5/+6 Reflex); <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this light, short cloak gains a bonus on all saving throws, as with a <Link to="/magic-wondrous/cloak_of_resistance">cloak of resistance</Link>, but the resistance bonus on Reflex saves is one greater. Furthermore, if the wearer fails a Reflex saving throw, she can expend one use of mythic power as an immediate action to reroll that saving throw. If the wearer fails the saving throw on the reroll, she can't use this ability again for 24 hours.</p>
<h3 id="magic-wondrous-cloak_of_quick_reflexes_1_2r-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/resistance">resistance</Link>, the creator must have the mythic saves ability; <strong>Cost</strong> 750 gp (+1, +2R), 3,000 gp (+2, +3R), 6,750 gp (+3, +4R), 12,000 gp (+4, +5R), 18,750 gp (+5/+6 Reflex)</p>
</>};
const _cloak_of_resistance = {title: "Cloak of Resistance", jsx: <><h2 id="magic-wondrous-cloak_of_resistance-cloak-of-resistance">Cloak of Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 507</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,000 gp (+1), 4,000 gp (+2), 9,000 gp (+3), 16,000 gp (+4), 25,000 gp (+5); <strong>Weight</strong> 1 lb.</p>
<p>Flecks of silver or steel are often sown amid the fabric of these magical cloaks. This garment offers magical protection in the form of a +1 to +5 resistance bonus on all saving throws (Fortitude, Reflex, and Will).</p>
<h3 id="magic-wondrous-cloak_of_resistance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resistance">resistance</Link>, creator's caster level must be at least three times the cloak's bonus; <strong>Cost</strong> 500 gp (+1), 2,000 gp (+2), 4,500 gp (+3), 8,000 gp (+4), 12,500 gp (+5)</p>
</>};
const _cloak_of_summer_and_winter_triaxian = {title: "Cloak of Summer and Winter (Triaxian)", jsx: <><h2 id="magic-wondrous-cloak_of_summer_and_winter_triaxian-cloak-of-summer-and-winter-triaxian">Cloak of Summer and Winter (Triaxian)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 230</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This quilted silk cloak is trimmed with thick white feathers. As a move action once per day, the wearer can whirl the cloak about himself to activate a <em>fire shield</em> effect. It activates as a warm shield if the ambient temperature is 65 degrees Fahrenheit or colder, or as a chill shield if the ambient temperature is 66 degrees Fahrenheit or hotter.</p>
<p>If the wearer is a <Link to="/race/triaxian">Triaxian</Link>, he gains energy resistance for as long as he wears the cloak. If he's summerborn, he gains fire resistance 10. If he's winterborn, he gains cold resistance 10. If he is transitional, he gains resistance 5 to both cold and fire.</p>
<h3 id="magic-wondrous-cloak_of_summer_and_winter_triaxian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fire_shield">fire shield</Link>, <Link to="/spell/resist_energy">resist energy</Link>, creator must be a Triaxian; <strong>Cost</strong> 15,000 gp</p>
</>};
const _cloak_of_the_bat = {title: "Cloak of the Bat", jsx: <><h2 id="magic-wondrous-cloak_of_the_bat-cloak-of-the-bat">Cloak of the Bat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 506</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Fashioned of dark brown or black cloth, this cloak bestows a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. The wearer is also able to hang upside down from the ceiling like a bat.</p>
<p>By holding the edges of the garment, the wearer is able to <em>fly</em> as per the spell (including a +7 bonus on <Link to="/skill/fly">Fly</Link> skill checks). If he desires, the wearer can actually polymorph himself into an ordinary bat and fly accordingly (as <em>beast shape III</em>). All possessions worn or carried are part of the transformation. Flying, either with the cloak or in bat form, can be accomplished only in darkness (either under the night sky or in a lightless or near-lightless environment underground). Either of the flying powers is usable for up to 7 minutes at a time, but after a flight of any duration the cloak cannot bestow any flying power for a like period of time.</p>
<h3 id="magic-wondrous-cloak_of_the_bat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _cloak_of_the_crusader = {title: "Cloak of the Crusader", jsx: <><h2 id="magic-wondrous-cloak_of_the_crusader-cloak-of-the-crusader">Cloak of the Crusader</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_103_the_hellfire_compact">Pathfinder #103: The Hellfire Compact pg. 73</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 55</Link>, <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 262</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This brilliant red cloak bears a golden symbol of an upright winged sword. The wearer can use <em>bless</em> once per day.</p>
<p>If <Link to="/faith/iomedae">Iomedae</Link> is the wearer's patron, the wearer gains a +1 enhancement bonus to her natural armor. As a standard action, the wearer can create an illusory image of Iomedae's banner, which floats 2 to 5 feet above the wearer's head and remains in place as long as the wearer is conscious. If the wearer has the banner class feature, she can use this battle standard as her banner.</p>
<h3 id="magic-wondrous-cloak_of_the_crusader-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/barkskin">barkskin</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/silent_image">silent image</Link>; <strong>Cost</strong> 1,350 gp</p>
</>};
const _cloak_of_the_diplomat = {title: "Cloak of the Diplomat", jsx: <><h2 id="magic-wondrous-cloak_of_the_diplomat-cloak-of-the-diplomat">Cloak of the Diplomat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 48</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The forest-green cloak grants a +5 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/sense_motive">Sense Motive</Link> checks. In addition, once per day, before making a Diplomacy or Sense Motive check, the wearer can decide to call upon the powers of the cloak to roll twice and take the better result. Finally, the wearer of this cloak can adjust a creature's attitude up to three steps when using Diplomacy, instead of the normal limit of two steps. However, the cloak's power does have one drawback. Should the wearer ever fail a Diplomacy checks made to adjust a creature's attitude by 5 or more, the creature's attitude is reduced by two steps instead of one.</p>
<h3 id="magic-wondrous-cloak_of_the_diplomat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, creator must have 5 ranks in Diplomacy and Sense Motive; <strong>Cost</strong> 10,000 gp</p>
</>};
const _cloak_of_the_duskwalker = {title: "Cloak of the Duskwalker", jsx: <><h2 id="magic-wondrous-cloak_of_the_duskwalker-cloak-of-the-duskwalker">Cloak of the Duskwalker</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dark, velvety cloak billows with a dramatic flourish in its wearer's wake. The cloak grants its wearer low-light vision. Once per day, on command, the wearer can surround herself with darkness, as the <em>darkness</em> spell. While this darkness is active, the cloak also grants the wearer darkvision 60 feet as well as low-light vision.</p>
<h3 id="magic-wondrous-cloak_of_the_duskwalker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkness">darkness</Link>, <Link to="/spell/darkvision">darkvision</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _cloak_of_the_hedge_wizard = {title: "Cloak of the Hedge Wizard", jsx: <><h2 id="magic-wondrous-cloak_of_the_hedge_wizard-cloak-of-the-hedge-wizard">Cloak of the Hedge Wizard</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 264</Link><br/><strong>Aura</strong> faint, school based on cloak type; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloak comes in eight varieties - one for each school of magic. The cloak grants its wearer the ability to use a certain number of spells on command (caster level 1st) based on its school of magic. It also grants the wearer the ability to use <em>prestidigitation</em> on command and at will.</p>
<ul>
<li><strong className="hl">Abjuration:</strong> at will-<Link to="/spell/resistance">resistance</Link>; 1/day-<Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/shield">shield</Link></li>
<li><strong className="hl">Conjuration:</strong> at will-<Link to="/spell/acid_splash">acid splash</Link>; 1/day-<Link to="/spell/mage_armor">mage armor</Link>, <Link to="/spell/unseen_servant">unseen servant</Link></li>
<li><strong className="hl">Divination:</strong> at will-<Link to="/spell/detect_magic">detect magic</Link>; 1/day-<Link to="/spell/detect_secret_doors">detect secret doors</Link>, <Link to="/spell/true_strike">true strike</Link></li>
<li><strong className="hl">Enchantment:</strong> at will-<Link to="/spell/daze">daze</Link>; 1/day-<Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/sleep">sleep</Link></li>
<li><strong className="hl">Evocation:</strong> at will-<Link to="/spell/light">light</Link>; 1/day-<Link to="/spell/floating_disk">floating disk</Link>, <Link to="/spell/magic_missile">magic missile</Link></li>
<li><strong className="hl">Illusion:</strong> at will-<Link to="/spell/ghost_sound">ghost sound</Link>; 1/day-<Link to="/spell/color_spray">color spray</Link>, <Link to="/spell/silent_image">silent image</Link></li>
<li><strong className="hl">Necromancy:</strong> at will-<Link to="/spell/touch_of_fatigue">touch of fatigue</Link>; 1/day-<Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/ray_of_enfeeblement">ray of enfeeblement</Link></li>
<li><strong className="hl">Transmutation:</strong> at will-<Link to="/spell/mage_hand">mage hand</Link>; 1/day-<Link to="/spell/enlarge_person">enlarge person</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link></li>
</ul>
<h3 id="magic-wondrous-cloak_of_the_hedge_wizard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link> and any spell the cloak allows the caster to use; the creator must have <Link to="/feat/spell_focus">Spell Focus</Link> in the cloak's school of magic; <strong>Cost</strong> 1,125 gp</p>
</>};
const _cloak_of_the_hunt = {title: "Cloak of the Hunt", jsx: <><h2 id="magic-wondrous-cloak_of_the_hunt-cloak-of-the-hunt">Cloak of the Hunt</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 150</Link><br/><strong>Aura</strong> strong illusion; <strong>CL</strong> 12th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This rough-spun green cloak is trimmed in wolf fur and fastened with a silver clasp. With the cloak drawn over his shoulders and the hood pulled up, the wearer becomes one with his surroundings, gaining a +5 bonus on <Link to="/skill/stealth">Stealth</Link> checks and on <Link to="/skill/survival">Survival</Link> skill checks made to follow tracks. The cloak also renders the wearer immune to the <Link to="/umr/scent">scent</Link> ability.</p>
<p>If the wearer expends one use of mythic power, the cloak turns him invisible for 1 hour, as <em>greater invisibility.</em> If the wearer makes an attack, the effects last for 1 minute after the attack, then end. A character made invisible by this cloak can't be detected with <Link to="/spell/detect_magic">detect magic</Link> or other spells or effects that detect magical auras. The greater invisibility can't be penetrated, revealed, or dispelled by spells of 2nd level or lower (such as <Link to="/spell/see_invisibility">see invisibility</Link> or <Link to="/spell/glitterdust">glitterdust</Link>), though <Link to="/spell/true_seeing">true seeing</Link> and <Link to="/magic-wondrous/dust_of_appearance">dust of appearance</Link> can reveal the wearer's presence.</p>
<h3 id="magic-wondrous-cloak_of_the_hunt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/greater_invisibility">greater invisibility</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _cloak_of_the_jungle = {title: "Cloak of the Jungle", jsx: <><h2 id="magic-wondrous-cloak_of_the_jungle-cloak-of-the-jungle">Cloak of the Jungle</h2>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony pg. 28</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>When this plain green cloak is worn with the hood drawn up around the head, the wearer can assume the form of a Large tree or shrub, as per the <em>tree shape</em> spell. The cloak is usable once per day, and the wearer may remain in tree form for up to 1 hour. The wearer can return to her normal form as a free action.</p>
<h3 id="magic-wondrous-cloak_of_the_jungle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/tree_shape">tree shape</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _cloak_of_the_manta_ray = {title: "Cloak of the Manta Ray", jsx: <><h2 id="magic-wondrous-cloak_of_the_manta_ray-cloak-of-the-manta-ray">Cloak of the Manta Ray</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 507</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloak appears to be made of leather until the wearer enters salt water. At that time, the cloak of the manta ray adheres to the individual, and he appears nearly identical to a <Link to="/monster/manta_ray">manta ray</Link> (as the <em>beast shape II</em> spell, except that it allows only manta ray form). He gains a +3 natural armor bonus, the ability to breathe underwater, and a swim speed of 60 feet, like a real manta ray.</p>
<p>The cloak also allows the wearer to attack with a sting ray's tail spine, dealing 1d6 points of damage. This attack can be used in addition to any other attack the character has, using his highest melee attack bonus. The wearer can release his arms from the cloak without sacrificing underwater movement if so desired.</p>
<h3 id="magic-wondrous-cloak_of_the_manta_ray-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _cloak_of_the_night_sky = {title: "Cloak of the Night Sky", jsx: <><h2 id="magic-wondrous-cloak_of_the_night_sky-cloak-of-the-night-sky">Cloak of the Night Sky</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 262</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 55</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dark hooded cloak is decorated with embroidered comets, moons, and stars along its edge. If the wearer sleeps while wearing the cloak, it protects him from hot and cold environments, as <em>endure elements,</em> and the wearer can sleep in medium armor without becoming fatigued. The wearer can use <em>know direction</em> once per day.</p>
<p>If <Link to="/faith/desna">Desna</Link> is the wearer's patron, as a standard action the wearer can cause additional celestial bodies to appear on the cloak so that they match the current configuration in the sky above the wearer. The wearer can use <em>longstrider</em> once per day. Once per day, the wearer can throw a tiny, white-burning meteor that acts as a <em>flare</em> effect. Some priests of Desna claim to have cloaks of this type that also allow them to travel from shadow to shadow when under a starry night sky.</p>
<h3 id="magic-wondrous-cloak_of_the_night_sky-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/flare">flare</Link>, <Link to="/spell/know_direction">know direction</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/longstrider">longstrider</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _cloak_of_the_saga_keeper = {title: "Cloak of the Saga Keeper", jsx: <><h2 id="magic-wondrous-cloak_of_the_saga_keeper-cloak-of-the-saga-keeper">Cloak of the Saga Keeper</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North pg. 28</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 13,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>Not all who board Ulfen longships or travel the paths of Kellid mammoth hunters are capable warriors, even though they may be just as brave. A cloak of the saga keeper is made from layers of fox fur and leather cut in strips reminiscent of fluttering lengths of scroll. Seven of these strips are dyed vibrant red. The wearer of the cloak constantly benefits from the effects of <Link to="/spell/endure_elements">endure elements</Link> while in cold conditions, and gains resist energy 2 against cold damage. Additionally, the wearer of the cloak can, as an immediate action, pluck one of the cloak's seven dyed strips to gain a +6 bonus to a <Link to="/skill/climb">Climb</Link>, <Link to="/skill/handle_animal">Handle Animal</Link>, <Link to="/skill/ride">Ride</Link>, <Link to="/skill/survival">Survival</Link>, or <Link to="/skill/swim">Swim</Link> check made that round. These strips dissolve immediately upon being plucked. Once all seven of the cloak's strips have been torn off, the wearer can no longer maker use of the cloak's skill-improving effects, but continues to benefit from the endure elements and resistance abilities.</p>
<h3 id="magic-wondrous-cloak_of_the_saga_keeper-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 6,900 gp</p>
</>};
const _cloak_of_the_scuttling_rat = {title: "Cloak of the Scuttling Rat", jsx: <><h2 id="magic-wondrous-cloak_of_the_scuttling_rat-cloak-of-the-scuttling-rat">Cloak of the Scuttling Rat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 155</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This unassuming cloak initially appears to be made of plain leather. When the wearer speaks the command word, however, the cloak of the scuttling rat wraps itself around her, transforming her into a <Link to="/monster/dire_rat">dire rat</Link> as if using <em>beast shape I.</em> The wearer can remain in dire rat form for up to 5 minutes per day. This duration need not be consecutive, but it must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-cloak_of_the_scuttling_rat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _cloak_of_the_sneaky_scoundrel = {title: "Cloak of the Sneaky Scoundrel", jsx: <><h2 id="magic-wondrous-cloak_of_the_sneaky_scoundrel-cloak-of-the-sneaky-scoundrel">Cloak of the Sneaky Scoundrel</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 228</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,400 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This dark burgundy cloak shifts its hue and pattern to blend in against its surroundings, granting the wearer a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. The cloak holds a concealed scabbard in which a light blade (as defined in the <Link to="/ability/weapon_groups">fighter weapon group</Link>) can be hidden. The wearer can draw the blade as if from a normal scabbard, but anyone searching the wearer for the item must succeed at a DC 20 <Link to="/skill/perception">Perception</Link> check, as if he were looking for a secret door.</p>
<p>If a <Link to="/class/swashbuckler">swashbuckler</Link> is wearing the cloak, she can spend 1 panache point to <em>vanish,</em> as the spell.</p>
<h3 id="magic-wondrous-cloak_of_the_sneaky_scoundrel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shrink_item">shrink item</Link>, <Link to="/spell/vanish">vanish</Link>; <strong>Cost</strong> 3,200 gp</p>
</>};
const _cloak_of_the_troll_king = {title: "Cloak of the Troll King", jsx: <><h2 id="magic-wondrous-cloak_of_the_troll_king-cloak-of-the-troll-king">Cloak of the Troll King</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 225</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This long cloak is a patchwork of beast and humanoid hides roughly stitched together. A crude, crown-shaped patch of yellow-dyed fabric is sewn on the back, and a length of knotted hemp rope secures the cloak around the wearer's neck. The wearer gains a +5 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and the ability to use <em>burning hands</em> as a spell-like ability three times per day.</p>
<h3 id="magic-wondrous-cloak_of_the_troll_king-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/burning_hands">burning hands</Link>, <Link to="/spell/cause_fear">cause fear</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _cloak_of_the_yeti = {title: "Cloak of the Yeti", jsx: <><h2 id="magic-wondrous-cloak_of_the_yeti-cloak-of-the-yeti">Cloak of the Yeti</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_67_the_snows_of_summer">Pathfinder #67: The Snows of Summer pg. 60</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This heavy cloak is crafted from shaggy white <Link to="/monster/yeti">yeti</Link> fur. When the cloak's hood is pulled up over the wearer's head, it takes on a semblance of its arctic namesake's fearsome visage. Northern warriors value its ability to ward against the chill of winter, as well as the protection it provides in combat. The cloak of the yeti provides a constant <em>endure elements</em> effect in cold weather (it has no effect in hot weather). In battle, the cloak wraps around the wearer, granting a +1 natural armor bonus. In addition, with the hood drawn over the wearer's head, the cloak grants a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> skill checks.</p>
<h3 id="magic-wondrous-cloak_of_the_yeti-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/barkskin">barkskin</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/endure_elements">endure elements</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _cloak_of_woodland_creatures = {title: "Cloak of Woodland Creatures", jsx: <><h2 id="magic-wondrous-cloak_of_woodland_creatures-cloak-of-woodland-creatures">Cloak of Woodland Creatures</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_115_trail_of_the_hunted">Pathfinder #115: Trail of the Hunted pg. 53</Link><br/><strong>Aura</strong> faint abjuration and conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This forest-green wool cloak is thick and warm. Its hem and the edge of its hood are embroidered with small figures of forest creatures (rabbits, squirrels, and the like) in white thread.</p>
<p>When worn, this cloak bestows a +1 resistance bonus on all saving throws. The wearer can remove the cloak at any time and lay it on the ground outdoors. This ends the resistance bonus but summons a number of animals from the cloak. The animals serve the character who summoned them for 10 minutes (or until slain or returned to the cloak's folds). A summoned creature can follow any of the commands described in the <Link to="/skill/handle_animal">Handle Animal</Link> skill. Use the following tables to determine what animals can be called forth.</p>
<p>The cloak summons creatures only when laid down outdoors on naturally occurring ground (not, for example, on a wooden deck or stone pathway). The cloak can be used to summon animals up to three times per day.</p>
<ScrollContainer id="magic-wondrous-cloak_of_woodland_creatures--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Animal</th>
</tr>
</thead>
<tbody><tr>
<td>01-30</td>
<td>1 <Link to="/monster/owl">owl</Link></td>
</tr>
<tr>
<td>31-60</td>
<td>1d3 <Link to="/monster/rat">rats</Link></td>
</tr>
<tr>
<td>61-75</td>
<td>1 <Link to="/monster/weasel">weasel</Link></td>
</tr>
<tr>
<td>76-90</td>
<td>1d6 <Link to="/monster/squirrel">squirrels</Link></td>
</tr>
<tr>
<td>91-100</td>
<td>1d4 <Link to="/monster/rabbit">rabbits</Link></td>
</tr>
</tbody></table></ScrollContainer>
<h3 id="magic-wondrous-cloak_of_woodland_creatures-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/summon_natures_ally_i">summon nature's ally I</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _cocoon_cloak = {title: "Cocoon Cloak", jsx: <><h2 id="magic-wondrous-cocoon_cloak-cocoon-cloak">Cocoon Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ruffled silk cloak is incredibly durable despite its soft, delicate construction. Anytime the wearer falls asleep (whether the sleep is natural or brought on by a magical effect), the cloak immediately transforms into sticky strands that envelop the wearer's body, hardening into a solid silk cocoon. While wrapped in the cocoon the wearer gains a +4 enhancement bonus to natural armor and is protected from critical hits and sneak attacks as if subject to the <Link to="/magic-enh/light_fortification">light fortification</Link> armor ability (25% chance for normal damage on a critical hit). The cocoon opens and transforms back into a cloak once the wearer awakens.</p>
<h3 id="magic-wondrous-cocoon_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/vermin_shape_i">vermin shape I</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _comforts_cloak = {title: "Comfort's Cloak", jsx: <><h2 id="magic-wondrous-comforts_cloak-comforts-cloak">Comfort's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link><br/><strong>Aura</strong> faint abjuration and necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 15,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>A favored cloak of rangers, this cloak is a patchwork of hides and fur. Comfort's cloak grants a constant <em>endure elements</em> effect to the wearer, and grants a +4 competence bonus to saves against disease, <Link to="/rule/energy_drain">energy drain</Link>, effects that cause <Link to="/misc/fatigue">fatigue</Link> or <Link to="/misc/exhaustion">exhaustion</Link>, and poisons. Furthermore, while the wearer is resting he <Link to="/rule/regain_hit_points">regains</Link> twice his Hit Dice in hit points for 8 hours of rest instead of the typical 1 hit point per Hit Die. When taking a full 24 hours of rest, the character regains 5 times his Hit Dice in hit points instead of twice his Hit Dice in hit points.</p>
<h3 id="magic-wondrous-comforts_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>; <strong>Cost</strong> 7,800 gp</p>
</>};
const _cowardly_crouching_cloak = {title: "Cowardly Crouching Cloak", jsx: <><h2 id="magic-wondrous-cowardly_crouching_cloak-cowardly-crouching-cloak">Cowardly Crouching Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 303</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,800 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This nondescript gray cloak has a hood that can fit over the wearer's entire face. The wearer can, as a move action, cover his face and drop to a huddling crouch. Any creature seeking to directly attack him while he does this must make a DC 11 Will save to do so (as the <em>sanctuary</em> spell). The wearer cannot see or take any actions while crouching. This makes him effectively <Link to="/misc/blind">blind</Link>, with all the normal penalties, but not <Link to="/misc/helpless">helpless</Link>. The wearer can end his crouch simply by standing up or moving.</p>
<h3 id="magic-wondrous-cowardly_crouching_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Cost</strong> 900 gp</p>
</>};
const _crow_brothers_cloak = {title: "Crow Brother's Cloak", jsx: <><h2 id="magic-wondrous-crow_brothers_cloak-crow-brothers-cloak">Crow Brother's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 53</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This flowing, black silken cloak glitters with an iridescent sheen like the feathers of a crow's wing. When the wearer moves, the fabric seems to dance on the air, as though it longed to take flight. The wearer can speak with birds while wearing the cloak, as if under the effects of <em>speak with animals.</em> Druids of northern Avistan have long favored these cloaks as a means of communicating with birds of the region, but they grew increasingly popular among several sects in Lirgen as well in the decades leading up to the Age of Lost Omens - despite the fact that crows themselves are not native to that particular land. Certainly, the exotic nature of the ebon feathers had an aesthetic appeal, for in a land where brightly colored songbirds were the norm, the concept of a midnight black avian couldn't help but to be somewhat intriguing to the residents.</p>
<p>As a move action, the wearer of a crow brother's cloak can command the item to dissolve into a swirling murder of crows, which faithfully surround the wearer for up to 13 rounds per day. These rounds need not be consecutive. The murder of crows functions as a <Link to="/monster/bat_swarm">bat swarm</Link>. The murder of crows deals no damage to the wearer and provides <Link to="/rule/concealment">concealment</Link> as long as the wearer remains within it. As a free action, the wearer can recall the swarm into cloak form or issue it a simple command (such as to direct its movement or to instruct it to follow the wearer). If the swarm is reduced to 0 hit points, it returns to its cloak form immediately and cannot be transformed again for 24 hours.</p>
<h3 id="magic-wondrous-crow_brothers_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, <Link to="/spell/summon_swarm">summon swarm</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _dead_mans_shroud = {title: "Dead Man's Shroud", jsx: <><h2 id="magic-wondrous-dead_mans_shroud-dead-mans-shroud">Dead Man's Shroud</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 55</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dirt-stained cloak was woven in shadow from the burial shroud of a condemned murderer. It prevents nonintelligent undead from detecting you, as per the <em>hide from undead</em> spell. Intelligent undead can perceive you if they succeed at a DC 11 Will save. The warding is ended if you touch an undead creature, <Link to="/ability/channel_energy">channel energy</Link> against undead, or attack any creature. Once per day as a standard action you can silently call forth the shadows bound into the shroud, rendering you invisible for 5 minutes.</p>
<h3 id="magic-wondrous-dead_mans_shroud-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hide_from_undead">hide from undead</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _deadened_shadows_cloak = {title: "Deadened Shadows Cloak", jsx: <><h2 id="magic-wondrous-deadened_shadows_cloak-deadened-shadows-cloak">Deadened Shadows Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 246</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 63,250 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Colored a muted gray, this cloak would be nondescript were it not for a single clasp of silver, stylized as a trio of skulls and inlaid with three large blue pearls. By pressing the first pearl as a move action, the wearer causes the <Link to="/rule/illumination_level">illumination level</Link> in a 30-foot radius to decrease by one step toward dim light, from bright light to normal light or from normal light to dim light. While active, the cloak also deadens the sounds the wearer makes (as <em>sculpt sound</em>). This prevents the wearer from communicating verbally, casting spells with verbal components, speaking command words, and so on. Pressing this pearl again suppresses this effect. This effect lasts for 15 minutes and can be used at will.</p>
<p>The second pearl also requires a move action to activate, and can be activated only while the first pearl is active. Activating the second pearl transports the wearer to the edge of the Material Plane where it borders the Shadow Plane. This functions as <em>shadow walk,</em> but only the wearer of the cloak is affected. This ability can be used once per week. While recharging, the second pearl changes color to a gleaming white. Once recharged, it returns to its former dark blue coloration.</p>
<p>The final pearl must be removed from the clasp and dropped as a move action. This breaks the jewel, causing wisps of shadowy vapor to engulf the wearer, granting him the benefits of <em>shadow body</em> for the following 15 minutes. Once destroyed, the third pearl can't be used again.</p>
<h3 id="magic-wondrous-deadened_shadows_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkness">darkness</Link>, <Link to="/spell/sculpt_sound">sculpt sound</Link>, <Link to="/spell/shadow_body">shadow body</Link>, <Link to="/spell/shadow_walk">shadow walk</Link>; <strong>Cost</strong> 31,625 gp</p>
</>};
const _deathlurkers_cloak = {title: "Deathlurker's Cloak", jsx: <><h2 id="magic-wondrous-deathlurkers_cloak-deathlurkers-cloak">Deathlurker's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 263</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 56</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This drab gray cloak billows about as if blown by an invisible wind. Once per day, the wearer can use <em>doom,</em> which causes a deathlike shadow to fleetingly cross the wearer's face.</p>
<p>If <Link to="/faith/groetus">Groetus</Link> is the wearer's patron, once per day the wearer can use <em>false life.</em> If the wearer successfully delivers a <Link to="/misc/coup_de_grace">coup de grace</Link> against a dying foe while <em>false life</em> is active, the wearer's <Link to="/rule/temporary_hit_points">temporary hit points</Link> from the <em>false life</em> effect increase by 1 (to a maximum of 20 temporary hit points). The dying creature must have at least as many Hit Dice as the wearer for this effect to occur.</p>
<h3 id="magic-wondrous-deathlurkers_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/doom">doom</Link>, <Link to="/spell/false_life">false life</Link>; <strong>Cost</strong> 1,350 gp</p>
</>};
const _demonspike_pauldrons = {title: "Demonspike Pauldrons", jsx: <><h2 id="magic-wondrous-demonspike_pauldrons-demonspike-pauldrons">Demonspike Pauldrons</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 265</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,350 gp; <strong>Weight</strong> 8 lbs.</p>
<p>These black iron pauldrons are studded with jagged spikes of various lengths. Demonspike pauldrons act as +2 <Link to="/eq-armorenh/armor_spikes">armor spikes</Link> and also deal 1d2 <Link to="/rule/bleed">bleed</Link> damage on a successful <Link to="/rule/grapple">grapple</Link> attack or melee attack made with the pauldrons. If these pauldrons are worn with normal armor spikes, increase the damage done by the armor spikes to 1d6 (Small) or 1d8 (Medium), and use the greater of the two enhancement bonuses to attack and damage - either from the armor spikes (if any) or the demonspike pauldrons.</p>
<h3 id="magic-wondrous-demonspike_pauldrons-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/bleed">bleed</Link>; <strong>Cost</strong> 7,175 gp</p>
</>};
const _dreamwing_cape = {title: "Dreamwing Cape", jsx: <><h2 id="magic-wondrous-dreamwing_cape-dreamwing-cape">Dreamwing Cape</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 263</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 17,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This knee-length cape is decorated with images of butterflies, moths, and stars. Once per day, the wearer can speak a command word to cause the cape to transform into a cloud of butterflies or moths. This functions as <em>cape of wasps,</em> except the swarm doesn't deal poison damage and deals full damage to incorporeal creatures. In addition, the wearer can use <em>glitterdust</em> once per day.</p>
<h3 id="magic-wondrous-dreamwing_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cape_of_wasps">cape of wasps</Link>, <Link to="/spell/glitterdust">glitterdust</Link>; <strong>Cost</strong> 8,750 gp</p>
</>};
const _eagle_cape = {title: "Eagle Cape", jsx: <><h2 id="magic-wondrous-eagle_cape-eagle-cape">Eagle Cape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Large eagle feathers decorate the back and arms of this magnificent cape. Should the cape's wearer fall more than 5 feet, the cape spreads out behind the wearer and she gently drifts to the ground. This acts exactly like a <em>feather fall</em> spell for the wearer only. Once per day, if the wearer grasps the edges of the cape and spreads her arms, she transforms into an <Link to="/monster/eagle">eagle</Link> (as per the <em>beast shape I</em> spell, except that it allows only eagle form and the wearer gains the eagle's full fly speed of 80 feet). This effect lasts for 10 minutes but can be ended prematurely as a standard action. In addition, while in eagle form, the wearer gains a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks.</p>
<h3 id="magic-wondrous-eagle_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/perceive_cues">perceive cues</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _ebony_bolero = {title: "Ebony Bolero", jsx: <><h2 id="magic-wondrous-ebony_bolero-ebony-bolero">Ebony Bolero</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 28</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Wisps of black smoke dance above these gray, <Link to="/race/fetchling">fetchling</Link>-made pauldrons. The wearer can manipulate these strands of shadow matter, assailing a target within 60 feet as a move action to create any of the effects listed below. All sustained effects last as long as the wearer concentrates to maintain them or up to 1 minute. The effects of these shadowy tendrils can be ignored with a successful DC 16 Will save. An ebony bolero has 5 charges, which regenerate at dusk each day. Each of the following assaults uses 1 charge.</p>
<ul>
<li><strong className="hl">Emotion:</strong> The wearer can smother a target's emotions as if by a <Link to="/spell/calm_emotions">calm emotions</Link> spell. Alternatively, the wearer can force a creature with the rage class ability to enter a raging state for at least 1 round (though the target can remain in this state longer if it chooses). The wearer can expend 2 charges when using this ability to increase the duration the target must rage to 3 rounds.</li>
<li><strong className="hl">Memory:</strong> The wearer can blot out the target's memories of events from the past minute. This functions as <Link to="/spell/modify_memory">modify memory</Link>, but can only eliminate memories.</li>
<li><strong className="hl">Thoughts:</strong> The wearer can delve into a target's mind and pluck out thoughts, as per <Link to="/spell/detect_thoughts">detect thoughts</Link>.</li>
<li><strong className="hl">Vision:</strong> The wearer can wind wisps of shadow matter around a creature's eyes, <Link to="/misc/blind">blinding</Link> it for as long as the wearer concentrates. Darkvision can't penetrate this supernatural darkness, but the <Link to="/umr/see_in_darkness">see in darkness</Link> universal monster ability can.</li>
</ul>
<h3 id="magic-wondrous-ebony_bolero-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shadow_conjuration">shadow conjuration</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _elusion_cloak = {title: "Elusion Cloak", jsx: <><h2 id="magic-wondrous-elusion_cloak-elusion-cloak">Elusion Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 29</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>Song-o <Link to="/race/halfling">halflings</Link> often use these cloaks to evade larger creatures in the jungles of the Mwangi Expanse. The wearer of an elusion cloak gains a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks against creatures of at least one size category larger than she is. In addition, once per day as a free action when the wearer fails a saving throw against a fear effect, she can gain the benefits of <em>expeditious retreat</em> for 5 rounds or for as long as she is affected by the fear effect, whichever is shorter.</p>
<h3 id="magic-wondrous-elusion_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>; <strong>Cost</strong> 1,800 gp</p>
</>};
const _entangling_aiguillette = {title: "Entangling Aiguillette", jsx: <><h2 id="magic-wondrous-entangling_aiguillette-entangling-aiguillette">Entangling Aiguillette</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This length of prickly green vine is woven into a living aiguillette worn around the shoulder. Once per day as an immediate action when the wearer is struck by a melee attack, she can compel the vine to uncoil and wrap around the attacker, causing the attacker to become <Link to="/rule/entangled">entangled</Link> (Reflex DC 13 negates). An entangled creature cannot move from its space. At the start of the entangled creature's turn, it can attempt a new saving throw against the entangling aiguillette, though the DC increases by 1 for each round the creature fails its save (to a maximum of 16 after 3 rounds). The entangled creature can also untangle itself as a move action by succeeding at a DC 13 Strength or <Link to="/skill/escape_artist">Escape Artist</Link> check. The entangling aiguillette's owner cannot move while entangling a creature, but can release an entangled creature as a free action.</p>
<h3 id="magic-wondrous-entangling_aiguillette-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/entangle">entangle</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _erinyes_company_cloak = {title: "Erinyes Company Cloak", jsx: <><h2 id="magic-wondrous-erinyes_company_cloak-erinyes-company-cloak"><Link to="/rule/aff_scarred_ladies">Erinyes Company</Link> Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 86</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This crimson cloak is trimmed with feathers taken from <Link to="/monster/erinyes">erinyes</Link> devils. Three times per day on command, the cloak transforms into a pair of black-feathered wings that grant the wearer a fly speed of 30 feet (average maneuverability) for 10 minutes. If the wearer is wearing <Link to="/eq-armor/gray_maiden_plate">Gray Maiden plate</Link>, its armor check penalty does not apply to the wearer's <Link to="/skill/fly">Fly</Link> checks. In addition, the wearer gains a +2 resistance bonus on all saving throws.</p>
<h3 id="magic-wondrous-erinyes_company_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _featherscale_cloak = {title: "Featherscale Cloak", jsx: <><h2 id="magic-wondrous-featherscale_cloak-featherscale-cloak">Featherscale Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 264</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This heavy linen cloak has a fish-scale pattern that darkens toward the bottom and white feathers on the shoulders. Once per day, the wearer can use <em>beast shape I,</em> but only to transform into a bird or fish. In addition, the wearer can use <em>hide from animals</em> (affecting only the wearer) once per day. The wearer gains a +5 competence bonus on <Link to="/skill/swim">Swim</Link> checks. Once per day, the wearer can use <em>feather fall.</em></p>
<h3 id="magic-wondrous-featherscale_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/hide_from_animals">hide from animals</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _golden_eagle_epaulets = {title: "Golden Eagle Epaulets", jsx: <><h2 id="magic-wondrous-golden_eagle_epaulets-golden-eagle-epaulets">Golden Eagle Epaulets</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 77</Link>, <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty pg. 26</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These decorative golden braids allow the wearer to cast <em>bless</em> and <em>sanctuary</em> each once per day. They also grant a +2 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> checks and checks for one other skill, depending on what branch of the <Link to="/rule/eagle_knights">Eagle Knights</Link> the epaulets are attuned to (<Link to="/skill/perception">Perception</Link> for the Steel Falcons, <Link to="/skill/ride">Ride</Link> for the Golden Legion, <Link to="/skill/swim">Swim</Link> for the Gray Corsairs, or <Link to="/skill/stealth">Stealth</Link> for the Twilight Talons).</p>
<h3 id="magic-wondrous-golden_eagle_epaulets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _grapsing_cloak = {title: "Grapsing Cloak", jsx: <><h2 id="magic-wondrous-grapsing_cloak-grapsing-cloak">Grapsing Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 30</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The long, threadbare tatters of this well-worn cloak coalesce into the rough form of a claw with opposable appendages, aiding the wearer with a helpful additional appendage when he might need it most. As a swift action, the wearer can use the cloak to retrieve any one small, stowed item carried on his person or any such unattended item within 5 feet. The wearer can hold one such item in the cloak, but he can't use the cloak to manipulate it (other than to put it in his hand) and can't wield a weapon or shield with the cloak. Additionally, once per day, the wearer can brace himself with the cloak's claw as a standard action, gaining a +4 competence bonus to CMD for 1 round. While the cloak is providing this bonus, it can't be used to hold or retrieve a stowed or unattended item</p>
<h3 id="magic-wondrous-grapsing_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_hand">mage hand</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _great_barghest_hero_cloak = {title: "Great Barghest Hero Cloak", jsx: <><h2 id="magic-wondrous-great_barghest_hero_cloak-great-barghest-hero-cloak">Great Barghest Hero Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 265</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 57</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloak looks like the skin of a <Link to="/monster/goblin_dog">goblin dog</Link>, including legs and tail; the clasp is a goblin dog's tooth. The wearer gains a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks.</p>
<p>If the wearer's patron is one of the goblin barghest hero gods (<Link to="/faith/hadregash">Hadregash</Link>, <Link to="/faith/venkelvore">Venkelvore</Link>, <Link to="/faith/zarongel">Zarongel</Link>, or <Link to="/faith/zogmugot">Zogmugot</Link>), once per day the wearer can use polymorph to transform into a goblin dog for up to 7 minutes.</p>
<h3 id="magic-wondrous-great_barghest_hero_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>, creator must have 5 ranks in Intimidate; <strong>Cost</strong> 1,400 gp</p>
</>};
const _groundbreaker_cloak = {title: "Groundbreaker Cloak", jsx: <><h2 id="magic-wondrous-groundbreaker_cloak-groundbreaker-cloak">Groundbreaker Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This heavy cloak is made from the hide of a <Link to="/monster/bulette">bulette</Link>, its thick gray leather heavily abraded and seemingly always dusty, and features a plated dorsal fin that protrudes from between the wearer's shoulders.</p>
<p>As a standard action, the wearer of a groundbreaker cloak can dive into the ground, gaining a burrow speed of 20 feet through sand, soil, gravel, and loose stone. While burrowing, the wearer cannot <Link to="/rule/run">run</Link> or <Link to="/rule/charge">charge</Link> and must travel along the surface, leaving the exposed dorsal plate visible from above. As the wearer burrows, displaced dirt swells before her and collapses behind her to create <Link to="/rule/difficult_terrain">difficult terrain</Link> in her wake. She has <Link to="/rule/cover">cover</Link> from attacks while burrowing. Unless the wearer has some other means of breathing while submerged, she must <Link to="/misc/hold_her_breath">hold her breath</Link> while burrowing. Emerging from the ground is a move action that doesn't provoke attacks of opportunity.</p>
<p>Once per day, the wearer can perform a charge attack by diving deep into the ground, burrowing up to 40 feet in a straight line (ignoring any obstacles that don't extend at least 10 feet into the ground) and bursting forth into a square adjacent to a target creature. This use of the cloak does not disturb the terrain as noted above, except where the wearer enters and exits the ground. The wearer ends this movement standing and the target of the charge is considered <Link to="/rule/flat_footed">flat-footed</Link> against the attack.</p>
<h3 id="magic-wondrous-groundbreaker_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>, <Link to="/spell/burrow">burrow</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _gunfighters_poncho = {title: "Gunfighter's Poncho", jsx: <><h2 id="magic-wondrous-gunfighters_poncho-gunfighters-poncho">Gunfighter's Poncho</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The abjurations woven into this woolen poncho not only defend against gunfire, but also insulate the wearer from dangerous magic. The wearer gains a +2 luck bonus to touch AC. Once per day as an immediate action, the wearer can negate a single ranged touched attack targeted at him, but cannot use this ability if the attack is a confirmed critical hit. When the wearer uses this ability, he must fall <Link to="/rule/prone">prone</Link>.</p>
<h3 id="magic-wondrous-gunfighters_poncho-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bullet_shield">bullet shield</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _harborwing_cloak = {title: "Harborwing Cloak", jsx: <><h2 id="magic-wondrous-harborwing_cloak-harborwing-cloak">Harborwing Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 22</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 5,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This white-hooded cloak is trimmed with seagull feathers. The cloak billows in the slightest breeze, and when the hood is drawn over the wearer's head, the cloak repels rainwater and seaspray, keeping the wearer dry. Harborwing cloaks were made by Varisian <Link to="/pclass/mystery_cultist">mystery cultists</Link> (and put to less-sacred uses by Sczarni bandits) for centuries before Magnimar's founding, though they are used more widely today. Many who worship Ylimancha, empyreal lord of coastal waters, fisherfolk, and flying creatures, wear these cloaks.</p>
<p>Three times per day, whenever the wearer of this cloak falls more than 5 feet, she can spend an immediate action to gain the benefits of <em>feather fall.</em> In addition, once per day, the wearer can command the cloak as a standard action to become a sheet of rippling, flowing water, causing attacks against her to take a 20% miss chance. While the cloak is in this liquid-like state, the wearer can use the <Link to="/skill/stealth">Stealth</Link> skill to hide in rainy conditions (or similar areas, such as the spray of a waterfall) even if she is being observed, and she gains a +5 circumstance bonus on Stealth checks in such conditions. This effect lasts for 3 minutes, and the duration need not be used all at once, but it must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-harborwing_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_water">create water</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/invisibility">invisibility</Link>, creator must worship <Link to="/faith/ylimancha">Ylimancha</Link>; <strong>Cost</strong> 2,600 gp</p>
</>};
const _highwaymans_cape = {title: "Highwayman's Cape", jsx: <><h2 id="magic-wondrous-highwaymans_cape-highwaymans-cape">Highwayman's Cape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 32,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This reversible multicolored cape marks the wearer's flamboyant audacity when turned with its bright colors outward, granting a +5 competence bonus on <Link to="/skill/bluff">Bluff</Link> checks. Reversible as a move action, the dappled camouflage of its other side grants a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. Regardless of the cape's current facing, the wearer can spend an immediate action at will to roll an <Link to="/skill/escape_artist">Escape Artist</Link> check against being grappled, bound, or restrained as if the cape targeted her with <em>liberating command.</em></p>
<h3 id="magic-wondrous-highwaymans_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/liberating_command">liberating command</Link>; <strong>Cost</strong> 16,250 gp</p>
</>};
const _hunters_cloak = {title: "Hunter's Cloak", jsx: <><h2 id="magic-wondrous-hunters_cloak-hunters-cloak">Hunter's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>Usually made from the skins of giant serpents, these cloaks are designed to help rangers, hunters, and trackers blend in with and travel quickly through the areas they are most familiar with. If the wearer has the <Link to="/ability/favored_terrain">favored terrain</Link> class ability and is traveling through one of his favored terrains, he can transform himself into an animal native to that environment. This works identically to the <em>beast shape I</em> spell, save that it is limited to creatures native to the environment (as defined in the appropriate Bestiary entry or per the GMs discretion). This effect lasts for 10 minutes per day. The duration need not be continuous, but it must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-hunters_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _hyena_spirit_skin = {title: "Hyena Spirit Skin", jsx: <><h2 id="magic-wondrous-hyena_spirit_skin-hyena-spirit-skin">Hyena Spirit Skin</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_39_the_city_of_seven_spears">Pathfinder #39: The City of Seven Spears pg. 55</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This ragged piece of fur and skin contains powerful magic. Once per day, when draped over the head and shoulders, the skin grants its wearer the physical characteristics of a <Link to="/monster/hyena">hyena</Link> for 10 minutes as the <em>aspect of the wolf</em> spell. The wearer gains a +4 enhancement bonus to Strength and Dexterity, the <Link to="/umr/scent">scent</Link> ability, and a +2 enhancement bonus on <Link to="/rule/trip">trip</Link> attacks, and she can make a trip combat maneuver as a swift action that does not provoke attacks of opportunity.</p>
<h3 id="magic-wondrous-hyena_spirit_skin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aspect_of_the_wolf">aspect of the wolf</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _immolation_cloak = {title: "Immolation Cloak", jsx: <><h2 id="magic-wondrous-immolation_cloak-immolation-cloak">Immolation Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 153</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 65,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>An immolation cloak grants its wearer resist fire 20. As a swift action, the wearer can command the cloak to burst into flame, providing the benefits of a <em>fire shield</em> (warm flames only). The wearer can dismiss the flames as a free action. The cloak can be used for a maximum of 10 rounds per day, which don't have to be consecutive.</p>
<p>By expending one use of mythic power, the cloak's wearer can recharge its immolation abilities. In addition, the wearer can expend one use of mythic power to detonate in a fiery explosion, dealing 1d8 points of fire damage per character level in a 30-foot-radius <Link to="/misc/spread">spread</Link>. A successful Reflex save (DC 10 + the wearer's mythic tier + the wearer's Charisma modifier) halves this damage. Though apparently destroyed in the explosion, the wearer reforms just prior to the start of his next turn in the space he exploded in (or the nearest open space if that space is unavailable).</p>
<h3 id="magic-wondrous-immolation_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/detonate">detonate</Link>, <Link to="/spell/fire_shield">fire shield</Link>, <Link to="/spell/resist_energy">resist energy</Link> (fire); <strong>Cost</strong> 32,500 gp</p>
</>};
const _iron_guard_pauldrons = {title: "Iron Guard Pauldrons", jsx: <><h2 id="magic-wondrous-iron_guard_pauldrons-iron-guard-pauldrons">Iron Guard Pauldrons</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 60</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 5,750 gp; <strong>Weight</strong> 6 lbs.</p>
<p>These simple, leather-strapped iron pauldrons are engraved with intricate images of icy winds and howling winter wolves, and are worn by senior members of the military order that serves <Link to="/monster/baba_yaga">Baba Yaga's</Link> interests across Irrisen. Iron guard pauldrons grant their wearer a +4 resistance bonus on saving throws against fire effects. If the wearer succeeds at a saving throw against an enemy's fire effect, the pauldrons shimmer with blue light for 5 rounds.</p>
<p>The wearer also gains a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. This bonus increases to +5 while the pauldrons cast blue light.</p>
<p>The wearer of the Iron Guard pauldrons gains the benefits of <em>endure elements,</em> but only for cold temperatures.</p>
<h3 id="magic-wondrous-iron_guard_pauldrons-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 2,875 gp</p>
</>};
const _jellyfish_cape = {title: "Jellyfish Cape", jsx: <><h2 id="magic-wondrous-jellyfish_cape-jellyfish-cape">Jellyfish Cape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 19,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This billowing white cape renders the wearer almost invisible the moment she is submerged in salt water, granting her <Link to="/rule/concealment">concealment</Link> (20% miss chance) so long as she remains entirely submerged. The wearer can breathe underwater and gains a swim speed of 20 ft. While the wearer is submerged, the cape surrounds her with tiny stinging tentacles. Any creature that ends its turn adjacent to the wearer takes 1 point of electricity damage and must succeed at a DC 16 Fortitude saving throw or be <Link to="/misc/sickened">sickened</Link> for 1 round. The sickened effect is a poison effect.</p>
<h3 id="magic-wondrous-jellyfish_cape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 9,600 gp</p>
</>};
const _juggernauts_pauldrons = {title: "Juggernaut's Pauldrons", jsx: <><h2 id="magic-wondrous-juggernauts_pauldrons-juggernauts-pauldrons">Juggernaut's Pauldrons</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These massive pauldrons take the shape of a pair of clenched fists made of beaten bronze. They bestow a +4 bonus on CMD, and grant the wearer the <Link to="/umr/ferocity">ferocity</Link> ability. On command, the wearer can increase its size, as though subject to an <em>enlarge person</em> spell, and can revert to regular size with another command. Three times per day, as an immediate action after the pauldrons' wearer kills an opponent, the wearer gains the benefit of the <em>deadly juggernaut</em> spell for 1 minute.</p>
<h3 id="magic-wondrous-juggernauts_pauldrons-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/deadly_juggernaut">deadly juggernaut</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _key_cloak = {title: "Key Cloak", jsx: <><h2 id="magic-wondrous-key_cloak-key-cloak">Key Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 32</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This short cloak is made of gold thread spun into a pattern of interlocking key shapes. The cloak grants the wearer a +1 shield bonus to AC. As a move action, the wearer can activate the cloak, which instantly produces enough keys to wrap the wearer in a dome-shaped shield of hardened metal, protecting the wearer as if he were carrying a <Link to="/eq-armor/tower_shield">tower shield</Link> with which he is proficient. While using this ability, the wearer can take no other actions (other than adjusting which direction the effective tower shield is considered to be facing) and is immobile. The wearer can remain in this form indefinitely, but resting in this form is equivalent to <Link to="/rule/armor">resting in heavy armor</Link>. The dome of keys can be dismissed as a swift action, and it automatically vanishes if the cloak is removed.</p>
<p>Once per day, the cloak can also create a single special <Link to="/eq-misc/skeleton_key">skeleton key</Link> as a standard action. This skeleton key can be tried on any one lock that uses a key, even if you aren't trained in the <Link to="/skill/disable_device">Disable Device</Link> skill. You use the key's Disable Device bonus of +15 rather than your own; you cannot take 10 when using a skeleton key. You can only attempt to open a particular lock with the skeleton key once. If the roll fails, the key is unable to open or close that lock. The key lasts for 1 hour and can be used on only a single lock during that time.</p>
<h3 id="magic-wondrous-key_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _lion_cloak = {title: "Lion Cloak", jsx: <><h2 id="magic-wondrous-lion_cloak-lion-cloak">Lion Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 266</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Made from a single male lion's coat with the mane surrounding its hood, the lion cloak is an impressive sight. A creature wearing the cloak gains a +2 resistance bonus on saving throws made against mind-affecting and fear effects and a +2 circumstance bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. Once per day, the wearer can pull the hood over her head, assuming the form of a <Link to="/monster/lion">lion</Link> (as the <em>beast shape II</em> spell, except that it allows only lion form) for up to 10 minutes. If the wearer has the smite class feature, she can use this power more than once per day by expending uses of her smite; at most she can take the lion form as many times as she has smites plus one additional time. While in this lion form the wearer cannot use its normal smite ability.</p>
<h3 id="magic-wondrous-lion_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _lycanthrope_skin_skinwalker_boar_rat_wolf = {title: "Lycanthrope Skin (Skinwalker) (boar, rat, wolf)", jsx: <><h2 id="magic-wondrous-lycanthrope_skin_skinwalker_boar_rat_wolf-lycanthrope-skin-skinwalker">Lycanthrope Skin (Skinwalker)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 233</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 24,000 gp (boar, rat, wolf), 40,000 gp (brown bear, bat, crocodile, shark, tiger); <strong>Weight</strong> 2 lbs.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This animal-skin cloak comes in eight varieties (one for each kind of <Link to="/race/skinwalker">skinwalker</Link>). The wearer gains the ability to speak with animals of the matching species and related species as per the spell <em>speak with animals.</em> For example, a werewolf skin allows the wearer to speak with canines. If the wearer is a skinwalker, and her skinwalker heritage matches that of the cloak, the wearer can take the listed animal's form as if using the change shape ability, gaining the base creature's size, form, and special abilities as per <em>beast shape I.</em> As normal for a skinwalker's transformation, her animal form lasts until she chooses to end it.</p>
<h3 id="magic-wondrous-lycanthrope_skin_skinwalker_boar_rat_wolf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, creator must be a skinwalker; <strong>Cost</strong> 12,000 gp (boar, rat, wolf), 20,000 gp (brown bear, bat, crocodile, shark, tiger)</p>
</>};
const _mantle_of_life = {title: "Mantle of Life", jsx: <><h2 id="magic-wondrous-mantle_of_life-mantle-of-life">Mantle of Life</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 220</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This short cape shimmers faintly under light. The wearer is immune to the <Link to="/umr/energy_drain">energy drain</Link> attacks made by undead creatures. She still suffers any other effects of the attack, but ignores the energy drain. If a corpse is wearing the mantle, it can't rise as an undead creature for any reason. This doesn't prevent creatures that were already undead from using abilities like rejuvenation to return to unlife.</p>
<h3 id="magic-wondrous-mantle_of_life-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_ward">death ward</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _mantle_of_spores = {title: "Mantle of Spores", jsx: <><h2 id="magic-wondrous-mantle_of_spores-mantle-of-spores">Mantle of Spores</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 13,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This mantle grants the wearer a +4 resistance bonus on saving throws against disease. Once per day, the wearer can flourish the cape as a swift action to surround himself with a cloud of deadly spores. Creatures adjacent to the wearer take 1d6 points of damage from the spores, plus 1d3 points of damage per round for 3 rounds as the spores grow into fuzzy green mold. After these rounds the mold becomes harmless, and can be washed away with a minute of scrubbing. The spores can be destroyed by making a DC 15 <Link to="/skill/heal">Heal</Link> check on an affected creature, or by effects that remove diseases. The spores are a disease effect.</p>
<h3 id="magic-wondrous-mantle_of_spores-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/contagion">contagion</Link>; <strong>Cost</strong> 6,700 gp</p>
</>};
const _mantle_of_the_darkest_night = {title: "Mantle of the Darkest Night", jsx: <><h2 id="magic-wondrous-mantle_of_the_darkest_night-mantle-of-the-darkest-night">Mantle of the Darkest Night</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 221</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This cloak is woven from a fabric of solid darkness held together by magic alone. When the wearer takes the <Link to="/misc/total_defense">total defense</Link> action, the mantle quickly dissolves into a globe of darkness (as per <em>deeper darkness</em>) that is centered on the wearer. The darkness coalesces into a mantle on the wearer's shoulders again at the beginning of her next turn unless she immediately uses another total defense action to maintain it. This effect functions up to 10 rounds per day.</p>
<p>If any of the item's daily uses are left, the wearer can grab the mantle and toss it into a space within 30 feet as a standard action. The mantle dissolves into a <em>deeper darkness</em> effect centered where the mantle landed and lasting for a number of rounds equal to the remaining daily uses. When the duration ends, the mantle materializes in the square into which the wearer threw it.</p>
<h3 id="magic-wondrous-mantle_of_the_darkest_night-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/deeper_darkness">deeper darkness</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _mantle_of_the_protector = {title: "Mantle of the Protector", jsx: <><h2 id="magic-wondrous-mantle_of_the_protector-mantle-of-the-protector">Mantle of the Protector</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 31</Link><br/><strong>Aura</strong> moderate abjuration and conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 12,200 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This silvery cloak has steel pauldrons built into it, and always seems to fit a little too loosely, no matter who happens to be wearing it. At the start of each day, the owner of a mantle of the protector may spend 10 minutes attuning the mantle to his armor and shield. He may then lend his attuned mantle to an ally, who can activate it as an immediate action at any time to gain the owner's armor and shield bonus as well as any other special properties the armor may have for 10 minutes. When the mantle is activated this way, the owner's armor and shield go dormant, and he loses any benefits they may provide for 1 minute.</p>
<h3 id="magic-wondrous-mantle_of_the_protector-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield_other">shield other</Link>; <strong>Cost</strong> 6,100 gp</p>
</>};
const _melding_cloak = {title: "Melding Cloak", jsx: <><h2 id="magic-wondrous-melding_cloak-melding-cloak">Melding Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 28</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloak is lined with thin strings of varying colors that shift in color to match surrounding material such as dirt, grass, or stone. This grants the wearer a +2 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. As a standard action, the wearer is able to physically meld into material such as wood, plaster, or stone (but not metal or other heavily worked materials), appearing as a dim shadow on the surface. The wearer can move across any exposed portion of the material at half her normal movement speed, allowing her to travel up walls or across floors. While melded with material in this manner, the wearer gains a +10 circumstance bonus on Stealth checks. The wearer can meld with material for up to 10 minutes per day. This duration need not be consecutive, but it must be spent in 1-minute increments.</p>
<p>Nearby creatures can notice the melded wearer with a successful <Link to="/skill/perception">Perception</Link> check. The wearer can be targeted normally while melded with material. If the wearer takes any damage while melded, or if the surface material is manipulated with <Link to="/spell/stone_shape">stone shape</Link>, <Link to="/spell/warp_wood">warp wood</Link>, or similar spells, the wearer is immediately shunted out of the material into the nearest open space.</p>
<h3 id="magic-wondrous-melding_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/passwall">passwall</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _moss_cloak = {title: "Moss Cloak", jsx: <><h2 id="magic-wondrous-moss_cloak-moss-cloak">Moss Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 165</Link>, <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 29</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 18,700 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A tangled layer of green moss grown on a thin, damp sheet of sod, this heavy cloak can be wrapped around the wearer to provide a measure of camouflage. When donned in forest or jungle terrain, a moss cloak gives its wearer a +10 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. In any terrain, the wearer can remove a single poison currently affecting him once per day as a standard action. This causes the moss to turn a sickly shade of brown as it draws the toxins from the wearer's body, negating the Stealth bonus until the cloak heals itself 24 hours later.</p>
<h3 id="magic-wondrous-moss_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/restoration">restoration</Link>; <strong>Cost</strong> 9,350 gp</p>
</>};
const _muleback_cords = {title: "Muleback Cords", jsx: <><h2 id="magic-wondrous-muleback_cords-muleback-cords">Muleback Cords</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 308</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1/4 lb.</p>
<p>These thick leather cords wrap around the wearer's biceps and shoulders. When worn, they make the wearer's muscles appear larger than normal. The wearer treats his Strength score as 8 higher than normal when determining his <Link to="/rule/carrying_capacity">carrying capacity</Link>. This bonus does not apply to combat, breaking items, or any other Strength-related rolls, it only contributes to the amount of equipment or material the wearer can carry.</p>
<h3 id="magic-wondrous-muleback_cords-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _murktouch_cloak = {title: "Murktouch Cloak", jsx: <><h2 id="magic-wondrous-murktouch_cloak-murktouch-cloak">Murktouch Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 61</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This lustrous crimson cloak has an ethereal quality to it, and is unnaturally light. When the wearer speaks the item's command word, a murktouch cloak dissolves into a vortex of red fog that churns around her and extends her awareness.</p>
<p>The fog forms a 15-foot-radius <Link to="/misc/emanation">emanation</Link> around the wearer and remains centered on her for as long as the cloak is activated. All creatures in the fog gain <Link to="/rule/concealment">concealment</Link> (20% miss chance), but the wearer has blindsight within the area. The vortex is unaffected by wind or any similar effect.</p>
<p>Whenever the wearer casts a spell or uses an ability that requires a successful touch attack, she can attempt that touch attack against any creature within the fog, even if she is not adjacent to the targeted creature.</p>
<p>The cloak can be activated for up to 10 rounds per day, though these rounds need not be consecutive. Its magic can be dismissed as a free action.</p>
<h3 id="magic-wondrous-murktouch_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/echolocation">echolocation</Link>, <Link to="/spell/fog_cloud">fog cloud</Link>, <Link to="/spell/mage_hand">mage hand</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _pauldrons_of_the_bull = {title: "Pauldrons of the Bull", jsx: <><h2 id="magic-wondrous-pauldrons_of_the_bull-pauldrons-of-the-bull">Pauldrons of the Bull</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These steel pauldrons are engraved with images of charging bulls. When their wearer makes a <Link to="/rule/bull_rush">bull rush</Link> combat maneuver, she can make the check twice and take the better result. Furthermore, they grant a +2 enhancement bonus to CMD against bull rushes.</p>
<h3 id="magic-wondrous-pauldrons_of_the_bull-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _pauldrons_of_the_jackass = {title: "Pauldrons of the Jackass", jsx: <><h2 id="magic-wondrous-pauldrons_of_the_jackass-pauldrons-of-the-jackass">Pauldrons of the Jackass</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 348</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Weight</strong> 3 lbs.</p>
<p>These steel pauldrons seem to be emblazoned with stampeding horses until they are worn, and then the horses change shape to that of dumfounded donkeys. The wearer of these pauldrons takes a -4 penalty to Dexterity and reduces all speeds by 10 feet. A successful <Link to="/spell/remove_curse">remove curse</Link> spell is required before this item can be removed.</p>
<h3 id="magic-wondrous-pauldrons_of_the_jackass-construction">Construction</h3>
<p><strong>Requirements</strong> any pauldrons; <strong>Cost</strong> -</p>
</>};
const _pauldrons_of_the_serpent = {title: "Pauldrons of the Serpent", jsx: <><h2 id="magic-wondrous-pauldrons_of_the_serpent-pauldrons-of-the-serpent">Pauldrons of the Serpent</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Constructed of <Link to="/eq-material/mithral">mithral</Link>, each of these pauldrons bears an embossed device of a viper coiled defensively. These pauldrons grant their wearer a +2 dodge bonus to AC against attacks of opportunity, and increase the wearer's CMD by 2 against <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/grapple">grapple</Link>, <Link to="/rule/reposition">reposition</Link>, and <Link to="/rule/trip">trip</Link> combat maneuvers.</p>
<h3 id="magic-wondrous-pauldrons_of_the_serpent-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _pauldrons_of_the_watchful_lion = {title: "Pauldrons of the Watchful Lion", jsx: <><h2 id="magic-wondrous-pauldrons_of_the_watchful_lion-pauldrons-of-the-watchful-lion">Pauldrons of the Watchful Lion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These steel and brass pauldrons feature two brass lion heads, one on each shoulder. Twice a day as an immediate action when a creature successfully makes an <Link to="/skill/acrobatics">Acrobatics</Link> check to move through the wearer's threatened area or its space without provoking an attack of opportunity, a shadowy lion can animate from one of the pauldrons and attack that creature. The attack uses the wearer's base attack bonus + Dexterity modifier and attacks the target's touch AC. On a hit, the lion deals 2d6 points of piercing damage (&times;2 critical).</p>
<h3 id="magic-wondrous-pauldrons_of_the_watchful_lion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/spectral_hand">spectral hand</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _pauldrons_of_unflinching_fortitude_1_2f = {title: "Pauldrons of Unflinching Fortitude (+1, +2F)", jsx: <><h2 id="magic-wondrous-pauldrons_of_unflinching_fortitude_1_2f-pauldrons-of-unflinching-fortitude">Pauldrons of Unflinching Fortitude</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 155</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,500 gp (+1, +2F), 6,000 gp (+2, +3F), 13,500 gp (+3, +4F), 24,000 gp (+4, +5F), 37,500 gp (+5/+6 Fortitude); <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these elegant, polished steel pauldrons gains a bonus on all saving throws, as with a <Link to="/magic-wondrous/cloak_of_resistance">cloak of resistance</Link>, but the resistance bonus on Fortitude saves is one greater. Furthermore, if the wearer fails a Fortitude saving throw, he can expend one use of mythic power as an immediate action to reroll that saving throw. If the wearer fails the saving throw on the reroll, he can't use this ability again for 24 hours.</p>
<h3 id="magic-wondrous-pauldrons_of_unflinching_fortitude_1_2f-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/resistance">resistance</Link>, the creator must have the mythic saves ability; <strong>Cost</strong> 750 gp (+1, +2F), 3,000 gp (+2, +3F), 6,750 gp (+3, +4F), 12,000 gp (+4, +5F), 18,750 gp (+5/+6 Fortitude)</p>
</>};
const _pelt_of_primal_power = {title: "Pelt of Primal Power", jsx: <><h2 id="magic-wondrous-pelt_of_primal_power-pelt-of-primal-power">Pelt of Primal Power</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North pg. 29</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>A prized item among Ulfen berserkers and vikings, a pelt of primal power is a large bearskin worn as a cloak, with the bear's head sitting atop the wearer's head. When donned, a pelt of primal power grants its wearer a +4 armor bonus to AC. In addition, once per day the wearer can transform into a <Link to="/monster/grizzly_bear">grizzly bear</Link> (as <em>beast shape II</em>) for up to 10 minutes.</p>
<h3 id="magic-wondrous-pelt_of_primal_power-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/mage_armor">mage armor</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _pelt_of_the_beast = {title: "Pelt of the Beast", jsx: <><h2 id="magic-wondrous-pelt_of_the_beast-pelt-of-the-beast">Pelt of the Beast</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 31</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 15,600 gp; <strong>Weight</strong> 8 lbs.</p>
<p>These lustrous animal pelts are particularly treasured among Ulfen barbarians. While any humanoid creature can don and use such pelts, their powers are vastly enhanced for <Link to="/race/skinwalker">skinwalkers</Link>. All pelts of the beast grant the following powers:</p>
<ul>
<li>A bite attack that <Link to="/umr/natural_attacks">deals damage</Link> appropriate to the wearer's size. If the wearer already has a bite attack, the critical threat range of this attack doubles. This does not stack with other magical effects that increase the threat range of a natural weapon.</li>
<li><em>Speak with animals</em> 1/day. If the wearer can already use <em>speak with animals</em> as a spell-like ability, she may do so at will.</li>
<li>The wearer may take the form of the animal from which the pelt came three times per day as if using <em>beast shape I</em>. In addition, if the wearer is a skinwalker, her change shape ability is enhanced so that she may gain an additional bestial feature when taking her bestial form, selectable from the skinwalker heritage tied to the animal from which the pelt came. For instance, a werewolf-kin wearing a bear pelt of the beast could use her change shape ability to gain a climb speed from the pelt's bestial features (identical to the set listed for werebear-kin) in addition to darkvision from her set of werewolf-kin bestial features. Feats or abilities that affect how many bestial features the skinwalker may gain at a single time stack with this ability.</li>
</ul>
<p>Each pelt also grants a competence bonus on a check, based on its type. These bonuses increase by 50% for skinwalkers wearing a pelt that matches their lycanthropic heritage.</p>
<ul>
<li><strong className="hl">Bat:</strong> +4 bonus on <Link to="/skill/perception">Perception</Link> checks in darkness</li>
<li><strong className="hl">Bear:</strong> +2 bonus on combat maneuver checks to <Link to="/rule/grapple">grapple</Link></li>
<li><strong className="hl">Boar:</strong> +2 bonus on combat maneuver checks to <Link to="/rule/bull_rush">bull rush</Link></li>
<li><strong className="hl">Crocodile:</strong> +2 bonus on combat maneuver checks to <Link to="/rule/sunder">sunder</Link></li>
<li><strong className="hl">Rat:</strong> +2 bonus on saving throws against disease</li>
<li><strong className="hl">Shark:</strong> +2 bonus on Perception and <Link to="/skill/swim">Swim</Link> checks attempted while completely underwater</li>
<li><strong className="hl">Tiger:</strong> +2 bonus on <Link to="/skill/stealth">Stealth</Link> checks</li>
<li><strong className="hl">Wolf:</strong> +2 bonus on combat maneuver checks to <Link to="/rule/trip">trip</Link></li>
</ul>
<p>Other pelts of the beast may be available at the GM's discretion.</p>
<h3 id="magic-wondrous-pelt_of_the_beast-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>; <strong>Cost</strong> 7,800 gp</p>
</>};
const _pelt_of_the_ulfen_wolf = {title: "Pelt of the Ulfen Wolf", jsx: <><h2 id="magic-wondrous-pelt_of_the_ulfen_wolf-pelt-of-the-ulfen-wolf">Pelt of the Ulfen Wolf</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 62</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,800 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This pelt of a large northern wolf is fashioned into a cloak. It can be activated up to five times per day. When struck in combat, the wearer can spend one use as a swift action to animate a ghostly <Link to="/monster/wolf">wolf</Link> from the pelt. This ghostly apparition strikes the creature that attacked the wearer with a wolf's bite attack. The wearer can spend one additional use each subsequent round to have the wolf continue attacking the target. The apparition can't be redirected, and disappears if the target moves more than 5 feet of the wearer or dies. The pelt can manifest only one wolf apparition at a time. Apart from these restrictions, the wolf can be directed as a <em>spiritual weapon</em> spell.</p>
<p>When a human wears a pelt of the Ulfen wolf, he gains a +1 morale bonus on saving throws against emotion effects. In addition, any round in which he begins his turn affected by a fear effect, he can attempt a new save at the beginning of the turn to reduce the severity of the fear effect from <Link to="/misc/panicked">panicked</Link> to <Link to="/misc/frightened">frightened</Link>, frightened to <Link to="/misc/shaken">shaken</Link>, or shaken to unaffected.</p>
<h3 id="magic-wondrous-pelt_of_the_ulfen_wolf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_fear">remove fear</Link>, <Link to="/spell/spiritual_weapon">spiritual weapon</Link>; <strong>Cost</strong> 7,400 gp</p>
</>};
const _petrifying_cloak = {title: "Petrifying Cloak", jsx: <><h2 id="magic-wondrous-petrifying_cloak-petrifying-cloak">Petrifying Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 348</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> shoulders; <strong>Weight</strong> 1 lb.</p>
<p>This gray magical cloak seems to be a protective cloak, but when it is donned, the wearer must succeed at a DC 20 Fortitude save or be instantly <Link to="/rule/petrified">petrified</Link>. If the initial saving throw succeeds, the creature wearing the cloak must make further checks at the start of each of its turns. On any failed saving throw the creature becomes petrified. A <Link to="/spell/remove_curse">remove curse</Link> or <Link to="/spell/stone_to_flesh">stone to flesh</Link> transforms the wearer back, at least long enough for someone to take the cloak off the wearer.</p>
<h3 id="magic-wondrous-petrifying_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> any cloak; <strong>Cost</strong> -</p>
</>};
const _phantom_entourage = {title: "Phantom Entourage", jsx: <><h2 id="magic-wondrous-phantom_entourage-phantom-entourage">Phantom Entourage</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 28</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>This fashionable silken shawl is incredibly light. Once per day on command, a phantom entourage surrounds its wearer with 1d4+2 illusions of attractive socialites. These illusions cluster closely around the wearer, laugh at his jokes, and generally stroke his ego with fawning flattery. This functions similarly to a <em>mirror image</em> spell, except an attacker has a 50% chance of ignoring the effect (as the illusions don't match the wearer). In addition, for every two illusory socialites the wearer currently has attending to him, he gains a +1 circumstance bonus on <Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, and <Link to="/skill/perform">Perform (sing)</Link> checks and takes a -2 penalty on <Link to="/skill/stealth">Stealth</Link> checks. This effect lasts for 6 hours.</p>
<h3 id="magic-wondrous-phantom_entourage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/spell/mirror_image">mirror image</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _phoenix_cloak = {title: "Phoenix Cloak", jsx: <><h2 id="magic-wondrous-phoenix_cloak-phoenix-cloak">Phoenix Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 156</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 55,000 gp; <strong>Weight</strong> 7 lbs.</p>
<p>This cloak is made of tough leather, and is decorated with brilliant red and orange feathers. As a free action, the wearer can rub her hands together, setting them alight - thus granting her natural attacks and unarmed strikes the <Link to="/umr/burn">burn</Link> special ability (1d6, Reflex DC 14). The wearer can use this ability for up to 10 rounds per day, which don't need to be consecutive.</p>
<p>If the wearer takes damage that would reduce her below 0 hit points, she can expend one use of mythic power to transform into a phoenix-like being. This doesn't require an action. When this happens, she is immediately affected as though targeted with a <em>breath of life</em> spell (CL 9th) and polymorphs into a bird-like creature made of flames (as <em>elemental body II,</em> CL 9; fire elemental only). While in this form, the wearer also gains a fly speed of 50 feet with good maneuverability, as well as a +4 bonus on <Link to="/skill/fly">Fly</Link> skill checks due to this maneuverability.</p>
<h3 id="magic-wondrous-phoenix_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/elemental_body_ii">elemental body II</Link>; <strong>Cost</strong> 27,500 gp</p>
</>};
const _plagueborn_mantle = {title: "Plagueborn Mantle", jsx: <><h2 id="magic-wondrous-plagueborn_mantle-plagueborn-mantle">Plagueborn Mantle</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 69</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>Made from the preserved skins of plague victims, this cloak functions as a <Link to="/magic-wondrous/cloak_of_resistance_1">cloak of resistance +1</Link>. If the wearer is infected with a disease, he can also command the mantle to cast <em>virulent miasma</em> once per day. Additionally, as a standard action, a diseased wearer can make a touch attack. If it hits, the target must succeed at a DC 15 Fortitude save or contract one disease the wearer currently has (wearer's choice in the case of multiple diseases).</p>
<h3 id="magic-wondrous-plagueborn_mantle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/contagion">contagion</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/virulent_miasma">virulent miasma</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _plumed_mantle = {title: "Plumed Mantle", jsx: <><h2 id="magic-wondrous-plumed_mantle-plumed-mantle">Plumed Mantle</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_34_blood_for_blood">Pathfinder #34: Blood for Blood pg. 69</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 39,550 gp; <strong>Weight</strong> -</p>
<p>This simple woolen cloak is trimmed across the shoulders with the feathers of eagles and other raptors, and permits the user to <em>fly</em> (as the spell) for a total of 30 minutes each day. These 30 minutes need not be consecutive, but each use of this ability that lasts for fewer than 5 minutes reduces the daily limit by 5 minutes. While flying under the power of the plumed mantle, the wearer has a +2 bonus on <Link to="/skill/fly">Fly</Link> checks, in addition to any bonuses from speed or maneuverability.</p>
<p>In addition to its powers of flight, the plumed mantle protects its wearer with a continuous <em>feather fall</em> effect, and makes him appear as a golden eagle to viewers on the ground. The wearer can suppress either effect by force of will as a free action.</p>
<p>While at a height greater than 40 feet, the wearer of the plumed mantle receives a +2 competence bonus on <Link to="/skill/perception">Perception</Link> checks involving vision or sight.</p>
<h3 id="magic-wondrous-plumed_mantle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/minor_image">minor image</Link>; <strong>Cost</strong> 19,775 gp</p>
</>};
const _poets_cloak = {title: "Poet's Cloak", jsx: <><h2 id="magic-wondrous-poets_cloak-poets-cloak">Poet's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 233</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 9,750 gp; <strong>Weight</strong> 1 lb.</p>
<p>Even after cleaning and mending, this traveler's cloak appears worn and weathered. For wearers with the <Link to="/ability/bardic_performance">bardic performance</Link> class feature, it grants the use of <Link to="/ability/raging_song">raging song</Link> as a 4th-level skald by spending rounds of bardic performance. For wearers with the raging song class feature, it grants the use of <Link to="/performance/inspire_courage">inspire courage</Link> and <Link to="/performance/inspire_competence">inspire competence</Link> as a 4th-level bard by spending rounds of raging song.</p>
<p>In addition, each poet's cloak allows its wearer to grant one specific <Link to="/ability/rage_powers">rage power</Link> when using raging song in place of his own rage powers (if any). The specific rage power varies by cloak. It must be usable by a 4th-level skald, and can't have any prerequisites other than level.</p>
<h3 id="magic-wondrous-poets_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/good_hope">good hope</Link>, <Link to="/spell/rage">rage</Link>, creator must have the bardic performance or raging song class feature; <strong>Cost</strong> 4,875 gp</p>
</>};
const _poisonous_cloak = {title: "Poisonous Cloak", jsx: <><h2 id="magic-wondrous-poisonous_cloak-poisonous-cloak">Poisonous Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 541</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> shoulders; <strong>Weight</strong> 1 lb.</p>
<p>This cloak is usually made of wool, although it can be made of leather. A <Link to="/spell/detect_poison">detect poison</Link> spell can reveal the presence of poison in the cloak's fabric. The garment can be handled without harm, but as soon as it is actually donned, the wearer takes 4d6 points of <Link to="/rule/constitution_damage">Constitution damage</Link> unless she succeeds on a DC 28 Fortitude save.</p>
<p>Once donned, a poisonous cloak can be removed only with a <Link to="/spell/remove_curse">remove curse</Link> spell; doing this destroys the magical property of the cloak. If a <Link to="/spell/neutralize_poison">neutralize poison</Link> spell is then used, it is possible to revive a dead victim with a <Link to="/spell/raise_dead">raise dead</Link> or <Link to="/spell/resurrection">resurrection</Link> spell.</p>
<h3 id="magic-wondrous-poisonous_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/cloak_of_arachnida">cloak of arachnida</Link>, <Link to="/magic-wondrous/cloak_of_the_bat">cloak of the bat</Link>, <Link to="/magic-wondrous/cloak_of_etherealness">cloak of etherealness</Link>, <Link to="/magic-wondrous/cloak_of_resistance_5">cloak of resistance +5</Link>, <Link to="/magic-wondrous/major_cloak_of_displacement">major cloak of displacement</Link>; <strong>Cost</strong> -</p>
</>};
const _prestidigitators_cloak = {title: "Prestidigitator's Cloak", jsx: <><h2 id="magic-wondrous-prestidigitators_cloak-prestidigitators-cloak">Prestidigitator's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 17,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This short black cloak grants its wearer a +8 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks. Furthermore, as a full-round action, the cloak can be removed and placed on an single object that takes up a 5-foot square or less and weighs 100 lbs. or less, at which point the object disappears and is stored within an extradimensional space within the cloak. The object can remain in the cloak for no more than 1 hour, at which point it falls out of the cloak in a square adjacent to the cloak or its wearer. The wearer can also command the cloak to dispel the object into an adjacent square.</p>
<h3 id="magic-wondrous-prestidigitators_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/rope_trick">rope trick</Link>; <strong>Cost</strong> 8,600 gp</p>
</>};
const _protean_cloak = {title: "Protean Cloak", jsx: <><h2 id="magic-wondrous-protean_cloak-protean-cloak">Protean Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 55</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 500 gp (+1 bonus), 2,000 gp (+2 bonus), 4,500 gp (+3 bonus), 8,000 gp (+4 bonus), 12,500 gp (+5 bonus); <strong>Weight</strong> 1 lb.</p>
<p>These multihued cloaks are as mutable as the <Link to="/family/protean">proteans</Link> that inspired them. The typical protean cloak appears to be crafted from the hide of a <Link to="/monster/naunet">naunet</Link> protean, but regardless of their apparent source, all protean cloaks shimmer and flicker with a riot of color. While the material feels scaly and rugose to the touch, a protean cloak flows like silk and does not hinder mobility.</p>
<p>A protean cloak provides a +1 to +5 resistance bonus on a single type of saving throw (typically Will saving throws). Once per day as a standard action, the wearer can change the type of saving throw that receives this bonus; the cloak then provides its bonus on the new type of saving throw until its type is changed again. If a protean cloak is unattended for more than 24 hours, the resistance bonus it applies automatically reverts back to Will saves.</p>
<h3 id="magic-wondrous-protean_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/entropic_shield">entropic shield</Link>, <Link to="/spell/resistance">resistance</Link>, creator must be chaotic, creator's caster level must be at least three times the cloak's bonus; <strong>Cost</strong> 250 gp (+1 bonus), 1,000 gp (+2 bonus), 2,250 gp (+3 bonus), 4,000 gp (+4 bonus), 6,250 gp (+5 bonus)</p>
</>};
const _quickchange_cloak = {title: "Quickchange Cloak", jsx: <><h2 id="magic-wondrous-quickchange_cloak-quickchange-cloak">Quickchange Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 267</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>One side of this reversible gray hooded cape is exquisitely embroidered and richly decorated, while the other appears shabby and worn. On command, by passing the edge of the cloak over her face, the wearer may remove a mundane disguise (one applied with the <Link to="/skill/disguise">Disguise</Link> skill) and store it in the cloak. This does not change the cloak's appearance in any way. Once a disguise is stored in the cloak, it can be reapplied to the wearer who placed it within the cloak on command, using the original result of the Disguise check. The cloak can store up to three disguises at once, and any wearer of the cloak can discard any number of disguises within the cloak as a free action.</p>
<h3 id="magic-wondrous-quickchange_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, creator must have at least 5 ranks in Disguise; <strong>Cost</strong> 750 gp</p>
</>};
const _quicksand_cloak = {title: "Quicksand Cloak", jsx: <><h2 id="magic-wondrous-quicksand_cloak-quicksand-cloak">Quicksand Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/tears_at_bitter_manor">Tears at Bitter Manor pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>The exterior of the cloak is an extradimensional space filled with water and sand. Each time a creature of the wearer's size or smaller attempts to <Link to="/rule/grapple">grapple</Link> the wearer, it must succeed at a DC 15 Reflex save or fail at the attempt and be engulfed by quicksand. Every round it's trapped in the extradimensional space, the trapped creature must make a <Link to="/skill/swim">Swim</Link> check (DC 15) to climb out, landing <Link to="/rule/prone">prone</Link> adjacent to the wearer. Crawling out doesn't provoke an attack of opportunity from the wearer, but does provoke from others. A creature that fails its Swim check by 5 or more submerges and begins to <Link to="/rule/drown">drown</Link>. A creature that succeeds at the initial save grapples the wearer normally, and doesn't need to save again unless the wearer escapes and the creature tries to grapple the wearer again.</p>
<p>A quicksand cloak left on the ground behaves as a patch of quicksand filling one 5-foot square, and swimming out works the same. Others may use <Link to="/rule/aid_another">aid another</Link> to help a creature trapped in the cloak, as though the creature were <Link to="/rule/grappled">grappled</Link>.</p>
<p>A quicksand cloak of any size can contain only one creature at a time; a creature attempting to grapple the wearer while the cloak already contains a body is not affected by the cloak.</p>
<h3 id="magic-wondrous-quicksand_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_water">create water</Link>, <Link to="/spell/shifting_sand">shifting sand</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _reapers_wisdom = {title: "Reaper's Wisdom", jsx: <><h2 id="magic-wondrous-reapers_wisdom-reapers-wisdom">Reaper's Wisdom</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 29</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 21,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This single, jade-encrusted <Link to="/spell/ironwood">ironwood</Link> pauldron glistens slightly, as if it were the reflective surface of a still pool, even in complete darkness. This pauldron increases the virulence of all poisons used by the wearer. Once per day, when attempting to poison a target, the wearer can speak a command word to magically enhance a single dose of poison, making it immune to the effects of <Link to="/spell/delay_poison">delay poison</Link>. The poison's DC is unaffected and the poison can still be affected by a <Link to="/spell/neutralize_poison">neutralize poison</Link> spell and similar magical effects.</p>
<h3 id="magic-wondrous-reapers_wisdom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/overwhelming_poison">overwhelming poison</Link>; <strong>Cost</strong> 10,800 gp</p>
</>};
const _rimepelt = {title: "Rimepelt", jsx: <><h2 id="magic-wondrous-rimepelt-rimepelt">Rimepelt</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_68_the_shackled_hut">Pathfinder #68: The Shackled Hut pg. 61</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,350 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This snow-white fur pelt of a <Link to="/monster/winter_wolf">winter wolf</Link> can be worn over the shoulders as a cloak. The pelt functions as furs, granting its wearer a +2 bonus on Fortitude saves to resist cold weather. The wearer can, as a standard action, transform into a Large winter wolf as if using <em>beast shape IV.</em> In certain special locations where winter wolves have the ability to take human form, such as the Howlings district of Whitethrone or the town of Redtooth, the wearer of a rimepelt in wolf form can take human form as winter wolves do, appearing as a whitehaired, blue-eyed human. In either wolf or human form, the wearer of a rimepelt smells like a winter wolf to other winter wolves and creatures with the <Link to="/umr/scent">scent</Link> ability. When the wearer returns to his normal form, or after 2 hours have elapsed, the rimepelt becomes a mundane winter wolf pelt.</p>
<p>Very rarely, a properly skinned winter wolf pelt manifests the properties of a rimepelt without requiring additional enchantment. A winter wolf whose pelt has such potential usually manifests some telltale physical attribute, such as heterochromatic eyes. Creating a rimepelt from such a rare creature requires a successful DC 25 <Link to="/skill/profession">Profession (hunter)</Link> or <Link to="/skill/survival">Survival</Link> check. Taking 20 is not allowed in this situation, and a failed check results in the pelt being utterly ruined for any use.</p>
<h3 id="magic-wondrous-rimepelt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iv">beast shape IV</Link>; <strong>Cost</strong> 1,675 gp</p>
</>};
const _rockfall_cloak = {title: "Rockfall Cloak", jsx: <><h2 id="magic-wondrous-rockfall_cloak-rockfall-cloak">Rockfall Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 8</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>A rockfall cloak is fashioned from rigid fabric with a stony texture, and it grants a +2 circumstance bonus on <Link to="/skill/stealth">Stealth</Link> checks in underground terrain. The wearer can command the cloak to encapsulate her as a free action. The cloak then hardens into a spherical stone shell resembling a smooth boulder that occupies an entire 5-foot square and weighs 200 pounds. The shell has a hardness of 10 and 25 hit points. Any damage from falling or from falling rocks is dealt to the stone shell. If it is destroyed, any remaining damage is transferred to its wearer. A rockfall cloak remains in this stone shell form for 1 hour (or earlier, if the wearer chooses) before crumbling to dust. Once it's used in its stone shell form, a rockfall cloak is destroyed.</p>
<h3 id="magic-wondrous-rockfall_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/stone_shield">stone shield</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _seafoam_shawl = {title: "Seafoam Shawl", jsx: <><h2 id="magic-wondrous-seafoam_shawl-seafoam-shawl">Seafoam Shawl</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 195</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This shawl of delicate lace can be activated once per day to grant the benefits of the <em>fins to feet</em> spell, transforming the wearer's lower fins or appendages into feet whenever he is on dry land - unless dismissed, this effect lasts for 5 hours.</p>
<h3 id="magic-wondrous-seafoam_shawl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fins_to_feet">fins to feet</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _shawl_of_life_keeping = {title: "Shawl of Life-Keeping", jsx: <><h2 id="magic-wondrous-shawl_of_life_keeping-shawl-of-life-keeping">Shawl of Life-Keeping</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 178</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This magical shawl is woven from silken, diaphanous material. Once per day, the wearer can speak a command word to transfer some of her life energy into the shawl (up to 10 hit points). If she is wearing the shawl and is reduced to -1 hit points or below, the shawl immediately heals her an amount equal to the number of hit points stored in the shawl. This healing cannot prevent the wearer from being killed. The life energy stored in the shawl lasts for 24 hours or until it heals the wearer, whichever comes first. If the shawl is destroyed, the stored life energy is lost.</p>
<p>While the shawl is storing a creature's life energy, it retains a connection to that creature. If another creature holds the shawl in its hand, the creature whose life energy is stored in the shawl takes a -2 penalty on Fortitude and Reflex saving throws against all effects from the current bearer of the shawl.</p>
<h3 id="magic-wondrous-shawl_of_life_keeping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/stabilize">stabilize</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _shawl_of_the_crone = {title: "Shawl of the Crone", jsx: <><h2 id="magic-wondrous-shawl_of_the_crone-shawl-of-the-crone">Shawl of the Crone</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The yarn making up this knitted gray wrap is frayed and tattered. As soon as a creature puts on the shawl, she immediately takes the form of a venerable female of her race (regardless of the wearer's actual gender) and remains so until the shawl is removed. Though this is an actual physical transformation, the wearer does not experience any infirmities due to <Link to="/rule/age">advanced age</Link>, including penalties to her physical attributes, nor does she gain any bonuses to her mental attributes. The wearer also gains a +4 circumstance bonus on any Charisma-based check intended to make her appear friendly, harmless, helpless, or otherwise in need of assistance or deserving of proper respect for someone of her apparent age. This bonus increases to +8 when directed against children. The wearer also counts as a <Link to="/family/hag">hag</Link> for the purposes of forming a coven, but this coven must always include at least one actual hag.</p>
<h3 id="magic-wondrous-shawl_of_the_crone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _shield_cloak = {title: "Shield Cloak", jsx: <><h2 id="magic-wondrous-shield_cloak-shield-cloak">Shield Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 4th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this rough, gray cloak can, as a move action, grasp the garment's edge and cause it to harden. The wearer can use the hardened edge it as if it were a <Link to="/rule/masterwork_a">masterwork</Link> <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link>. Using the cloak in this fashion imposes no armor check penalty, but does impose a 5% arcane spell failure chance. The edge of the cloak can be dropped and made pliant again as a free action. Shield enhancement bonuses and special abilities can be added to the cloak as if it were a masterwork shield.</p>
<h3 id="magic-wondrous-shield_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _shroud_of_venom = {title: "Shroud of Venom", jsx: <><h2 id="magic-wondrous-shroud_of_venom-shroud-of-venom">Shroud of Venom</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 29</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This green leather cloak has blue hues and flows gently in the wind when worn, giving the wearer the appearance of donning a cresting wave on her shoulders. This cloak causes any liquid poisons poured onto it to immediately crystallize and blend into the leather, providing the wearer a +5 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal poisons on her person. In addition, as a full-round action, the wearer can pour up to 3 doses of poison onto the cloak, which requires a successful DC 15 <Link to="/skill/craft">Craft (alchemy)</Link> check. A natural 1 on this check exposes the wearer to the poison. Any poisons poured onto the cloak last for 1 hour before becoming inert. As a standard action that provokes attacks of opportunity, the wearer can scrape off the crystallized poison onto her weapon and use it as if she had applied the poison to it normally. Doing this does not put the wearer at risk for being poisoned.</p>
<h3 id="magic-wondrous-shroud_of_venom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/delay_poison">delay poison</Link>, <Link to="/spell/obscure_poison">obscure poison</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _skelterhide = {title: "Skelterhide", jsx: <><h2 id="magic-wondrous-skelterhide-skelterhide">Skelterhide</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_117_assault_on_longshadow">Pathfinder #117: Assault on Longshadow pg. 30</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This thick hide cloak grants its wearer the divided mind of a <Link to="/monster/skeltercat">skeltercat</Link>. While worn, the cloak imparts a +1 resistance bonus on Fortitude and Reflex saves and a +2 resistance bonus on Will saves. In addition, once per round, the wearer can reroll the percentile dice when determining her actions while <Link to="/misc/confused">confused</Link> and choose the desired result. Once the cloak is donned, the wearer cannot speak or write; she can communicate only in unintelligible growls. The wearer still understands language as normal.</p>
<p>If the wearer suffers from one or more permanent mental afflictions that alter her behavior, such as <Link to="/spell/insanity">insanity</Link> or the effects of a <Link to="/magic-wondrous/helm_of_opposite_alignment">helm of opposite alignment</Link>, for 15 minutes per day she can function as if unaffected by these conditions. This time does not need to be used all at once, but must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-skelterhide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _slashing_cloak = {title: "Slashing Cloak", jsx: <><h2 id="magic-wondrous-slashing_cloak-slashing-cloak">Slashing Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thick burgundy cloak is trimmed with <Link to="/eq-material/mithral">mithral</Link> plates and cut to fit handsomely over heavy armor. As a full-round action, the wearer can spin in his space, damaging each creature within 5 feet. This attack uses the wearer's highest base attack bonus against each creature, and deals 2d6 damage on a hit. The wearer is considered proficient with this attack. Furthermore, the cloak can be <Link to="/main/magic_enhancements">magically enhanced</Link> like a melee weapon, adding the cost of the melee weapon property to the cloak's cost.</p>
<h3 id="magic-wondrous-slashing_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blade_barrier">blade barrier</Link>; <strong>Cost</strong> 10,000 gp; <strong>Cost</strong> 10,000 gp</p>
</>};
const _soothing_stole = {title: "Soothing Stole", jsx: <><h2 id="magic-wondrous-soothing_stole-soothing-stole">Soothing Stole</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 23</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Snowborn frequently fight off hostile enemies of both the intelligent and animalistic varieties. The smart <Link to="/race/half_elf">half-elf</Link> knows that he can't lose a fight that never begins and makes every attempt to stave off combat. This white fur stole helps the wary snowborn, or anyone else, temporarily calm down opponents. While wearing this stole, the wearer gains a +2 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> checks to improve someone's attitude and on <Link to="/ability/wild_empathy">wild empathy</Link> checks to improve an animal's attitude. Three times per day on command, the wearer can activate the stole to gain a 20-foot radius aura of either <em>calm animals</em> or <em>calm emotions</em> for 1 minute (Will DC 13 negates). The stole also functions as <Link to="/eq-misc/cold_weather_outfit">cold weather clothing</Link>.</p>
<h3 id="magic-wondrous-soothing_stole-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_animals">calm animals</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>; <strong>Cost</strong> 3,250 gp</p>
</>};
const _stole_of_justice = {title: "Stole of Justice", jsx: <><h2 id="magic-wondrous-stole_of_justice-stole-of-justice">Stole of Justice</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This long stole of unrelenting black is marked on one end with golden scales and the other with the embroidered image of hooded justice. The wearer gains a +5 competence bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks and can create a <em>zone of truth</em> for up to 5 minutes per day; these rounds need not be consecutive. When the wearer uses <Link to="/spell/detect_chaos">detect chaos</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_good">detect good</Link>, or <Link to="/spell/detect_law">detect law</Link>, at the beginning of her next turn after casting she gains information as if she had concentrated for 3 full rounds. Finally, if the wearer is an <Link to="/class/inquisitor">inquisitor</Link>, when using her judgment she receives a bonus on <Link to="/skill/perception">Perception</Link> checks and her combat maneuver defense as if she were wielding a <Link to="/magic-enh/jurist">jurist</Link> weapon.</p>
<h3 id="magic-wondrous-stole_of_justice-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/zone_of_truth">zone of truth</Link>, creator must have 5 ranks of Sense Motive; <strong>Cost</strong> 9,000 gp</p>
</>};
const _stone_cloak_minor = {title: "Stone Cloak (Minor)", jsx: <><h2 id="magic-wondrous-stone_cloak_minor-stone-cloak">Stone Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 268-9</Link><br/><strong>Aura</strong> faint (minor) or moderate (major) abjuration; <strong>CL</strong> 5th (minor), 8th (major)<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 10,000 gp (minor), 20,000 gp (major); <strong>Weight</strong> 1 lb.</p>
<p><strong className="hl">Minor:</strong> This mottled gray cloak looks like granite or some other light gray stone. The wearer can pull a minor stone cloak tight around herself and freeze in place as a move action, which causes the cloak to harden like the stone it resembles. When she does this, the wearer can take no actions other than free actions and is denied her Dexterity bonus to AC but gains DR 5/adamantine. She also gains a +5 circumstance bonus to <Link to="/skill/stealth">Stealth</Link> checks while protected in this manner. This effect can be dismissed as a free action.</p>
<p><strong className="hl">Major:</strong> This cloak is identical to the <em>minor stone cloak,</em> save that it provides DR 10/adamantine when activated.</p>
<h3 id="magic-wondrous-stone_cloak_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/stone_shape">stone shape</Link> (minor) or <Link to="/spell/stoneskin">stoneskin</Link> (major); <strong>Cost</strong> 5,000 gp (minor), 10,000 gp (major)</p>
</>};
const _stonemist_cloak = {title: "Stonemist Cloak", jsx: <><h2 id="magic-wondrous-stonemist_cloak-stonemist-cloak">Stonemist Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 201</Link><br/><strong>Aura</strong> faint conjuration and illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>In rocky or mountainous areas, when this stone-gray cloak is worn with the hood drawn up around the head, the wearer gains a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. Once per day, the wearer can create an area of fog equivalent to <em>obscuring mist.</em></p>
<h3 id="magic-wondrous-stonemist_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _swordlords_cloak = {title: "Swordlord's Cloak", jsx: <><h2 id="magic-wondrous-swordlords_cloak-swordlords-cloak">Swordlord's Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 26</Link><br/><strong>Aura</strong> faint abjuration and divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 4,000 gp (+1 bonus), 16,000 gp (+2 bonus), 37,000 gp (+3 bonus), 64,000 gp (+4 bonus), 100,000 gp (+5 bonus); <strong>Weight</strong> 1 lb.</p>
<p>This exotic, fur-trimmed cloak is decorated with golden filigree. In addition to offering magical protection, the cloak guides a skilled wearer's blade to block attacks. Such cloaks are often commissioned by Aldori Academy graduates when they attain <Link to="/pclass/aldori_swordlord">swordlord</Link> status.</p>
<p>A swordlord's cloak acts as a <Link to="/magic-wondrous/cloak_of_resistance">cloak of resistance</Link>. In addition, whenever the wearer is benefiting from the defensive parry class feature, he receives an insight bonus to his AC equal to the cloak's resistance bonus.</p>
<h3 id="magic-wondrous-swordlords_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/anticipate_peril">anticipate peril</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 2,000 gp (+1 bonus), 8,000 gp (+2 bonus), 18,500 gp (+3 bonus), 32,000 gp (+4 bonus), 50,000 gp (+5 bonus)</p>
</>};
const _tentacle_cloak = {title: "Tentacle Cloak", jsx: <><h2 id="magic-wondrous-tentacle_cloak-tentacle-cloak">Tentacle Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Subtle, indefinable shapes ripple and flow when this deep blue cloak moves, seemingly devouring any light falling upon it. Once per day at the wearer's command, two large gray tentacles emerge from the cloak near the shoulders. Each tentacle can make a natural attack that deals 1d6 points of bludgeoning damage, assuming the wear is Medium (the damage of the tentacles scales by size of the wearer as a <Link to="/umr/natural_attack">tentacle natural attack</Link>). The tentacles have 10-foot reach and the <Link to="/umr/grab">grab</Link> monster special ability. In addition, the wearer gains a +4 competence bonus on <Link to="/rule/grapple">grapple</Link> maneuver checks with the tentacles. The tentacles last for 1 minute.</p>
<h3 id="magic-wondrous-tentacle_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _treeform_cloak = {title: "Treeform Cloak", jsx: <><h2 id="magic-wondrous-treeform_cloak-treeform-cloak">Treeform Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This long green cloak's back features an embroidered image of an ancient oak. Once per day on command, the wearer can assume the shape of a tree, as the <em>tree shape</em> spell, but can only take the form of a living tree. Furthermore, each hour the wear spends in tree form while in direct sunlight, he heals 1d6 hit points.</p>
<h3 id="magic-wondrous-treeform_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/goodberry">goodberry</Link>, <Link to="/spell/tree_shape">tree shape</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _wings_of_flying = {title: "Wings of Flying", jsx: <><h2 id="magic-wondrous-wings_of_flying-wings-of-flying">Wings of Flying</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 532</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 54,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A pair of these wings might appear to be nothing more than a plain cloak of old, black cloth, or they could be as elegant as a long cape of blue feathers. When the wearer speaks the command word, the cloak turns into a pair of bat or bird wings that empower her to fly with a speed of 60 feet (average maneuverability), also granting a +5 competence bonus on <Link to="/skill/fly">Fly</Link> skill checks.</p>
<h3 id="magic-wondrous-wings_of_flying-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 27,000 gp</p>
</>};
const _wings_of_flying_lesser = {title: "Wings of Flying (Lesser)", jsx: <><h2 id="magic-wondrous-wings_of_flying_lesser-wings-of-flying-lesser">Wings of Flying (Lesser)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_63_the_asylum_stone">Pathfinder #63: The Asylum Stone pg. 59</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This mechanical backpack is a mess of gears and cogs, with two large canvas wings extending out from it to rise over the wearer's shoulders. When the wearer touches the button on the pack's chest harness, the wings whir to life and begin flapping rapidly, hauling the wearer awkwardly into the air.</p>
<p>Lesser wings of flying grant the wearer a fly speed of 30 feet (poor maneuverability).</p>
<h3 id="magic-wondrous-wings_of_flying_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _wings_of_the_gargoyle = {title: "Wings of the Gargoyle", jsx: <><h2 id="magic-wondrous-wings_of_the_gargoyle-wings-of-the-gargoyle">Wings of the Gargoyle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 72,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These cloth shoulder straps have many pebbles stitched into them. The wearer of the straps can command them to unfurl a pair of wings made from a hard gray stone. These wings grant her a fly speed of 60 feet and average maneuverability. When these wings are present her skin also takes on a noticeable stone-like appearance and she gains DR 10/adamantine. The wearer can furl and unfurl these wings as a swift action. The wings can be used for up to 5 minutes each day. The duration need not be continuous, but it must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-wings_of_the_gargoyle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 36,000 gp</p>
</>};
const _wyvern_cloak = {title: "Wyvern Cloak", jsx: <><h2 id="magic-wondrous-wyvern_cloak-wyvern-cloak">Wyvern Cloak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 269</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> shoulders; <strong>Price</strong> 78,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This heavy cloak is made of blue scaled leather and has a pointed hem that hangs near the ground. The cloak provides the wearer a +4 resistance bonus on Will saves, a continuous <em>feather fall</em> effect (as the spell), and the ability to use <em>fly</em> once per day. At will as a swift action, the wearer can form the hem into a stinger, granting her a sting natural weapon. This sting deals 1d6 points of damage plus <em>poison</em> (as the spell; DC 16). Reverting the stinger to its normal, inconspicuous shape is a free action.</p>
<h3 id="magic-wondrous-wyvern_cloak-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/poison">poison</Link>, <Link to="/spell/resistance">resistance</Link>, creator must be at least caster level 12; <strong>Cost</strong> 39,300 gp</p>
</>};
const _anchoring_bracers = {title: "Anchoring Bracers", jsx: <><h2 id="magic-wondrous-anchoring_bracers-anchoring-bracers">Anchoring Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These iron bracers are covered in hooks and small claws. They strap firmly to the wearer's forearms and can be used to make attacks as <Link to="/eq-weapon/spiked_gauntlet">spiked gauntlets</Link>.</p>
<p>Three times per day, the bracers' wearer can telekinetically anchor herself to a foe within 190 feet as a full-round action. This requires a combat maneuver check, which doesn't provoke an attack of opportunity. The wearer gains a +2 circumstance bonus on this check for every size category by which her target is larger than she.</p>
<p>On a successful check, either the wearer or the target (whichever weighs less) moves to be adjacent to the other (moving to the closest free adjacent space). This movement does not provoke attacks of opportunity. For 1 minute, the wearer and target are kept adjacent by the power of the bracers. Each is able to move only by succeeding at an opposed Strength check, and always takes the other along even if successful.</p>
<p>Additionally, both the wearer and the target are unable to engage in dimensional travel for this duration, as if under the effect of a <Link to="/spell/dimensional_anchor">dimensional anchor</Link> spell. The wearer of the anchoring bracers can dismiss the anchoring effect before the end of its duration as a standard action.</p>
<h3 id="magic-wondrous-anchoring_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _armband_of_the_golden_serpent = {title: "Armband of the Golden Serpent", jsx: <><h2 id="magic-wondrous-armband_of_the_golden_serpent-armband-of-the-golden-serpent">Armband of the Golden Serpent</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_82_secrets_of_the_sphinx">Pathfinder #82: Secrets of the Sphinx pg. 62</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Heavy golden coils form this serpentine armband. It wraps snugly around the upper arm of its wearer and stays firmly in place once donned.</p>
<p>An armband of the golden serpent allows its wearer to cast spells with the range of touch in melee combat without provoking attacks of opportunity. Spells with ranges other than touch provoke attacks of opportunity as normal - even spells with a range of personal. When the wearer of an armband of the golden serpent casts a touch spell in melee combat, the armband animates, slithering down the wearer's arm and striking to deliver the touch attack. Although the armband delivers the spell, the wearer is still required to take the necessary actions and make the required attack roll; the wearer does not gain any additional actions.</p>
<h3 id="magic-wondrous-armband_of_the_golden_serpent-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/combat_casting">Combat Casting</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spectral_hand">spectral hand</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _armbands_of_the_brawler = {title: "Armbands of the Brawler", jsx: <><h2 id="magic-wondrous-armbands_of_the_brawler-armbands-of-the-brawler">Armbands of the Brawler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These scarred and worn armbands have clearly seen rough use, and are constructed out of coarse leather and fastened with thick leather straps. They grant their wearer a +1 competence bonus on <Link to="/rule/grapple">grapple</Link> checks and checks to break a grapple.</p>
<h3 id="magic-wondrous-armbands_of_the_brawler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _armigers_panoply = {title: "Armiger's Panoply", jsx: <><h2 id="magic-wondrous-armigers_panoply-armigers-panoply">Armiger's Panoply</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 30</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lbs.</p>
<p>An armiger's panoply is a magic item set made up of one pair of bracers and a large leather sack. The bracers are normally forearm guards made in the style of <Link to="/rule/masterwork_a">masterwork</Link> <Link to="/eq-armor/padded">padded</Link> or <Link to="/eq-armor/quilted_cloth">quilted cloth</Link> armor. They are often made of silk or high-quality linen, though they can also be crafted of leather or even chain links. A command word is normally inscribed on the inside of one of the bracers. The sack can be used to store a single suit of armor, including a shield. The armor retains its normal weight when stored. If items other than a suit of armor and a shield are put in the sack, they immediately fall through.</p>
<p>Three times per day, the wearer of the bracers can speak the panoply's command word to have the suit of armor and shield stored in the sack teleport onto the wearer. The sack must be within 500 feet of the wearer of the bracers in order to function. If the wearer is already in a suit of armor, it is teleported into the sack at the same time the new armor is teleported onto the user's body. As long as the armor to be worn is the same size as the user, it fits perfectly and doesn't interfere with anything else worn or hindering the user, including any grapple or tight space the wearer might be trapped in.</p>
<h3 id="magic-wondrous-armigers_panoply-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/effortless_armor">effortless armor</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _arrowmasters_bracers = {title: "Arrowmaster's Bracers", jsx: <><h2 id="magic-wondrous-arrowmasters_bracers-arrowmasters-bracers">Arrowmaster's Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 13,900 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple pair of leather shooting bracers are designed to protect the wearer's wrist from being snapped by bowstrings. They appear similar to a set of <Link to="/magic-wondrous/bracers_of_archery_lesser">bracers of archery</Link>, but a wearer notices the difference as soon as she dons them.</p>
<p>The wearer of these bracers gains damage reduction 5/magic against ranged weapons, as well as a +1 deflection bonus against ranged attacks. In addition, once per day, as a swift action, the wearer can grant herself a +20 insight bonus on her next ranged attack roll before the end of her next turn.</p>
<h3 id="magic-wondrous-arrowmasters_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/protection_from_arrows">protection from arrows</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 6,950 gp</p>
</>};
const _bands_of_unbreakable_camaraderie = {title: "Bands of Unbreakable Camaraderie", jsx: <><h2 id="magic-wondrous-bands_of_unbreakable_camaraderie-bands-of-unbreakable-camaraderie">Bands of Unbreakable Camaraderie</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 147</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>While worn, this pair of plain steel armbands limits the ability of the wearer to strike out against his comrades with weapon attacks, in the event he is unable to control his own actions (such as if <Link to="/misc/confused">confused</Link> or dominated) or unable to distinguish friends from foes (such as if <Link to="/misc/blinded">blinded</Link>). The armbands grow heavier and hinder the wearer's momentum under these circumstances, causing him to take a -4 penalty on attack rolls against creatures he would otherwise consider allies.</p>
<p>Alternatively, two creatures can each wear one of the armbands, occupying the wrist slot for both. Under these conditions, the bands apply only half the normal penalty on attack rolls against allies. However, the two wearers ignore each other for any effects that would cause them to attack the closest creature, unless one wearer purposefully attacks the other. Even if the wearers do attack one another, their attacks take the full -4 penalty, always fail to confirm critical hits, and deal nonlethal damage only.</p>
<h3 id="magic-wondrous-bands_of_unbreakable_camaraderie-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/battlemind_link">battlemind link</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _bone_beads = {title: "Bone Beads", jsx: <><h2 id="magic-wondrous-bone_beads-bone-beads">Bone Beads</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_48_shadows_of_gallowspire">Pathfinder #48: Shadows of Gallowspire pg. 35</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This bracelet of tiny carved skulls allows its wearer to command up to 8 HD worth of mindless undead creatures as the <em>command undead</em> spell. It is a standard action to establish control over an undead creature, and a free action to relinquish control. If the wearer attempts to control more than 8 HD of undead, the new creatures fall under the wearer's control, and any previously controlled undead in excess of this amount become uncontrolled.</p>
<h3 id="magic-wondrous-bone_beads-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/command_undead">command undead</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _bonebreaker_bracers = {title: "Bonebreaker Bracers", jsx: <><h2 id="magic-wondrous-bonebreaker_bracers-bonebreaker-bracers">Bonebreaker Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These thick brass and leather bracers allow the wearer to tear through bone and muscle like paper. Once per day, as part of a melee attack, the wearer can activate the bracers to inflict a horrific injury on an opponent. If the attack hits, the target must make a DC 14 Will save. If the save fails, the bracers reduce the target's Strength, Dexterity, or Constitution (wearer's choice) by -6. This penalty cannot reduce the target's ability score below 1. The injury heals over time, reducing the penalty by 1 for each day that passes since the time of the injury, and is immediately removed by <Link to="/spell/heal">heal</Link>, <Link to="/spell/regenerate">regenerate</Link>, <Link to="/spell/restoration">restoration</Link>, or any magic that can break a curse.</p>
<h3 id="magic-wondrous-bonebreaker_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _bracelet_of_bargaining = {title: "Bracelet of Bargaining", jsx: <><h2 id="magic-wondrous-bracelet_of_bargaining-bracelet-of-bargaining">Bracelet of Bargaining</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 14,500 gp; <strong>Weight</strong> -</p>
<p>This heavy gold band can be worn openly as a display of wealth or concealed beneath a sleeve. It grants its wearer a +5 competence bonus on <Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, and <Link to="/skill/sense_motive">Sense Motive</Link> checks. Whenever the wearer shakes hands with another creature In order to seal a deal or a promise, she can immediately sense whether deceit is involved (Will save DC 16 negates), though the wearer cannot determine the exact nature of the deception.</p>
<h3 id="magic-wondrous-bracelet_of_bargaining-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/discern_lies">discern lies</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>; <strong>Cost</strong> 7,250 gp</p>
</>};
const _bracelet_of_friends = {title: "Bracelet of Friends", jsx: <><h2 id="magic-wondrous-bracelet_of_friends-bracelet-of-friends">Bracelet of Friends</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 19,000 gp; <strong>Weight</strong> -</p>
<p>This silver charm bracelet has four charms upon it when created. The owner may designate one person known to him to be keyed to each charm. (This designation takes a standard action, but once done it lasts forever or until changed.) When a charm is grasped and the name of the keyed individual is spoken, that person is called to the spot (a standard action) appearing at the user's location along with his gear, as long as the bracelets's owner and the called person are on the same plane. The keyed individual knows who is attempting to teleport him, and the bracelet of friends only functions on willing travelers. Once a charm is activated, it disappears. Charms separated from the bracelet are worthless. A bracelet found with fewer than four charms is worth 25% less for each missing charm.</p>
<h3 id="magic-wondrous-bracelet_of_friends-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/refuge">refuge</Link>; <strong>Cost</strong> 9,500 gp</p>
</>};
const _bracelet_of_good_luck_charms_halfling = {title: "Bracelet of Good Luck Charms (Halfling)", jsx: <><h2 id="magic-wondrous-bracelet_of_good_luck_charms_halfling-bracelet-of-good-luck-charms-halfling">Bracelet of Good Luck Charms (Halfling)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 229</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 4th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This bronze bracelet has seven charms shaped like symbols of good luck in halfling society. It works only for a wearer with the luck or adaptable luck racial trait. At any time, a <Link to="/race/halfling">halfling</Link> wearer can choose to reroll a roll without taking an action. She must take the new result even if it is worse. When the wearer uses this ability, one of the bracelet's charms crumbles to dust. When all the charms are spent, the bracelet becomes nonmagical. The wearer can remove a charm from the bracelet and give it to another creature to grant that creature the charm's ability to reroll die rolls, but if unused before the next sunrise, the charm turns to dust anyway.</p>
<h3 id="magic-wondrous-bracelet_of_good_luck_charms_halfling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, creator must be a halfling; <strong>Cost</strong> 8,000 gp</p>
</>};
const _bracelet_of_mercy = {title: "Bracelet of Mercy", jsx: <><h2 id="magic-wondrous-bracelet_of_mercy-bracelet-of-mercy">Bracelet of Mercy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 300</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This metal bracelet is set with multiple gems blessed by a priest. If the wearer has the <Link to="/ability/lay_on_hands">lay on hands</Link> class feature, she can use it one additional time per day and is always treated as if she has the <Link to="/mercy/diseased">diseased</Link> mercy. If the wearer already has that mercy, her effective caster level for removing diseases increases by +4.</p>
<h3 id="magic-wondrous-bracelet_of_mercy-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_disease">remove disease</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _bracelet_of_second_chances = {title: "Bracelet of Second Chances", jsx: <><h2 id="magic-wondrous-bracelet_of_second_chances-bracelet-of-second-chances">Bracelet of Second Chances</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 270</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 51</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 15,750 gp; <strong>Weight</strong> -</p>
<p>This bracelet is adorned with seven coral beads carved in intricate designs. When a critical hit or <Link to="/ability/sneak_attack">sneak attack</Link> is confirmed on the wearer, as an immediate action before damage is rolled, he can choose to convert the critical hit into a normal hit. Each time the wearer negates a critical hit or sneak attack in this manner, one bead shatters. When all seven are used up, the bracelet itself crumbles into powder.</p>
<h3 id="magic-wondrous-bracelet_of_second_chances-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/breath_of_life">breath of life</Link>; <strong>Cost</strong> 7,875 gp</p>
</>};
const _bracelets_of_defiant_wind = {title: "Bracelets of Defiant Wind", jsx: <><h2 id="magic-wondrous-bracelets_of_defiant_wind-bracelets-of-defiant-wind">Bracelets of Defiant Wind</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_83_the_slave_trenches_of_hakotep">Pathfinder #83: The Slave Trenches of Hakotep pg. 69</Link><br/><strong>Aura</strong> moderate conjuration and evocation [air]; <strong>CL</strong> 10th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>These azure-and-white marbled bracelets feel smooth and perpetually cool to the touch. When worn, they activate once per day as an immediate action to safeguard against sudden airborne attacks and effects by automatically surrounding their wearer in a cylinder of pure wind and elemental air. This effect functions simultaneously as both <em>air bubble</em> and <em>wind wall,</em> protecting against missile weapons, gases, and most gaseous breath weapons. It also activates underwater if the wearer begins to <Link to="/rule/drowning">drown</Link>. Once activated, the effect lasts for 10 rounds.</p>
<h3 id="magic-wondrous-bracelets_of_defiant_wind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_bubble">air bubble</Link>, <Link to="/spell/contingency">contingency</Link>, <Link to="/spell/wind_wall">wind wall</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _bracelets_of_stone = {title: "Bracelets of Stone", jsx: <><h2 id="magic-wondrous-bracelets_of_stone-bracelets-of-stone">Bracelets of Stone</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 7</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 26,760 gp; <strong>Weight</strong> 4 lbs.</p>
<p>These rugged stone armbands slip on easily and swiftly adjust to a size appropriate for the wearer. Once per day, the wearer can create a <em>wall of stone</em> up to 2 inches thick and 45 feet long (or 90 feet long, if the thickness is reduced to 1 inch). For the purpose of this effect, the bracelets of stone count as a stone surface that the <em>wall of stone</em> can merge with, and they magically provide the wearer the strength necessary to support any <em>wall of stone</em> so created. Thus, the wearer can create a bridge or wall in nearly any location as long as he is standing adjacent to a point where the bracelets can connect to it. If the bracelets are used this way, the wearer can't move from this space and is considered <Link to="/rule/flat_footed">flat-footed</Link> during this time, but may end the effect as an immediate action (thus destroying the wall). If either bracelet is taken off or a portion of the wall is breached or destroyed, this effect immediately ends and the <em>wall of stone</em> crumbles to dust.</p>
<h3 id="magic-wondrous-bracelets_of_stone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/wall_of_stone">wall of stone</Link>; <strong>Cost</strong> 13,380 gp</p>
</>};
const _bracers_of_archery_greater = {title: "Bracers of Archery (Greater)", jsx: <><h2 id="magic-wondrous-bracers_of_archery_greater-bracers-of-archery-greater">Bracers of Archery (Greater)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 271</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> faint (lesser) or moderate (greater) transmutation; <strong>CL</strong> 4th (lesser), 8th (greater)<br/><strong>Slot</strong> wrists; <strong>Price</strong> 5,000 gp (lesser), 25,000 gp (greater); <strong>Weight</strong> 1 lb.</p>
<p>These bracers look like normal protective wear. They empower the wearer to use any bow (not including crossbows) as if she were proficient in its use. If she already has proficiency with any type of bow, she gains a +2 competence bonus on attack rolls and a +1 competence bonus on damage rolls whenever using that type of bow. Both bracers must be worn for the magic to be effective.</p>
<p><strong className="hl">Lesser bracers of archery</strong> are typically constructed of lighter material. They function as greater bracers of archery, except they grant a +1 competence bonus on attack rolls and no bonus on damage rolls.</p>
<h3 id="magic-wondrous-bracers_of_archery_greater-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, crafter must be proficient with a longbow or shortbow; <strong>Cost</strong> 2,500 gp (lesser), 12,500 gp (greater)</p>
</>};
const _bracers_of_armor = {title: "Bracers of Armor", jsx: <><h2 id="magic-wondrous-bracers_of_armor-bracers-of-armor">Bracers of Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 271</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 1,000 gp (+1), 4,000 gp (+2), 9,000 gp (+3), 16,000 gp (+4), 25,000 gp (+5), 36,000 gp (+6), 49,000 gp (+7), 64,000 gp (+8); <strong>Weight</strong> 1 lb.</p>
<p>These items appear to be wrist or arm guards, sometimes etched with symbols of protection or depictions of vigilant-looking animals. Bracers of armor surround the wearer with an invisible but tangible field of force, granting him an armor bonus of +1 to +8, just as though he were wearing armor. Both bracers of armor must be worn for the magic to be effective.</p>
<p>Alternatively, bracers of armor can be enchanted with armor special abilities. See <Link to="/rule/tea_armor_special_abilities">Table 3-3: Armor Special Abilities</Link> for a list of abilities. Special abilities usually count as additional bonuses for determining the market value of an item, but do not improve AC. Bracers of armor cannot have a modified bonus (armor bonus plus armor special ability bonus equivalents) higher than +8. Bracers of armor must have at least a +1 armor bonus to grant an armor special ability. Bracers of armor cannot have any armor special abilities that add a flat gp amount to their cost. Bracers of armor and ordinary armor do not stack. If the wearer receives a larger armor bonus from another source, the bracers of armor cease functioning and do not grant their armor bonus or their armor special abilities. If the bracers of armor grant a larger armor bonus, the other source of armor ceases functioning.</p>
<h3 id="magic-wondrous-bracers_of_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_armor">mage armor</Link>, creator's caster level must be at least two times that of the bonus placed on the bracers, plus any requirements of the armor special abilities; <strong>Cost</strong> 500 gp (+1), 2,000 gp (+2), 4,500 gp (+3), 8,000 gp (+4), 12,500 gp (+5), 18,000 gp (+6), 24,500 gp (+7), 32,000 gp (+8)</p>
</>};
const _bracers_of_celestial_intervention = {title: "Bracers of Celestial Intervention", jsx: <><h2 id="magic-wondrous-bracers_of_celestial_intervention-bracers-of-celestial-intervention">Bracers of Celestial Intervention</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 20</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Prayers and engravings of celestial beings cover these golden bracers. A paladin can expend one or more of her uses of smite evil into these bracers as a standard action to call forth agathions, angels, or archons to aid her. This acts as a <em>summon monster</em> spell of a spell level equal to the number of smite evil uses the paladin expends. Outsiders summoned with the bracers must be from the list detailed in the <em>summon monster</em> spell.</p>
<h3 id="magic-wondrous-bracers_of_celestial_intervention-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_monster_vii">summon monster VII</Link>, creator must be lawful good; <strong>Cost</strong> 8,000 gp</p>
</>};
const _bracers_of_defenselessness = {title: "Bracers of Defenselessness", jsx: <><h2 id="magic-wondrous-bracers_of_defenselessness-bracers-of-defenselessness">Bracers of Defenselessness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 344</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 540</Link></p>
<p><strong>Aura</strong> strong conjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> wrists; <strong>Weight</strong> 1 lb.</p>
<p>These bejeweled and shining bracers initially appear to be <em>bracers of armor +5</em> and actually serve as such until the wearer is attacked in anger by an enemy with a Challenge Rating equal to or greater than her level. At that moment and thereafter, the bracers bestow a -5 penalty to AC. Once their curse is activated, bracers of defenselessness can be removed only by means of a <Link to="/spell/remove_curse">remove curse</Link> spell.</p>
<h3 id="magic-wondrous-bracers_of_defenselessness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/bracers_of_armor_5">bracers of armor +5</Link>; <strong>Cost</strong> -</p>
</>};
const _bracers_of_falcons_aim = {title: "Bracers of Falcon's Aim", jsx: <><h2 id="magic-wondrous-bracers_of_falcons_aim-bracers-of-falcons-aim">Bracers of Falcon's Aim</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Each of these crimson leather bracers is emblazoned with the image of a soaring golden falcon scanning the ground for easy prey. Once per day, on command, the wearer gains the benefits of <em>aspect of the falcon</em> for 1 minute. The wearer must wear these bracers continuously for 24 hours before activating this ability.</p>
<h3 id="magic-wondrous-bracers_of_falcons_aim-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aspect_of_the_falcon">aspect of the falcon</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _bracers_of_might = {title: "Bracers of Might", jsx: <><h2 id="magic-wondrous-bracers_of_might-bracers-of-might">Bracers of Might</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 148</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These golden bracers are sculpted to depict a pair of mighty stags rearing up in triumph. They grant a +4 bonus on all Strength ability checks and Strength-based skill checks. As a swift action up to three times per day, the wearer can call upon the power of these bracers to gain a +4 sacred bonus to Strength for 1 round. The wearer can expend one use of mythic power to treat one Strength ability check or Strength-based skill check as if he rolled a natural 20.</p>
<h3 id="magic-wondrous-bracers_of_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _bracers_of_primal_mastery = {title: "Bracers of Primal Mastery", jsx: <><h2 id="magic-wondrous-bracers_of_primal_mastery-bracers-of-primal-mastery">Bracers of Primal Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 30</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Seven <Link to="/eq-material/mithral">mithral</Link> strips weave their way around these steel bracers, which thrum ever so faintly with the force of stabilizing magic. When the wearer activates a magic item, casts a spell, or uses a spell-like ability that triggers a <Link to="/rule/primal_magic">primal magic</Link> event, the resulting event is rolled (or otherwise determined) twice, and the caster can choose which of the two events occur. The bracers also allow the wearer to roll twice and choose the result when using a <Link to="/magic-rod/rod_of_wonder">rod of wonder</Link>.</p>
<h3 id="magic-wondrous-bracers_of_primal_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _bracers_of_steadiness = {title: "Bracers of Steadiness", jsx: <><h2 id="magic-wondrous-bracers_of_steadiness-bracers-of-steadiness">Bracers of Steadiness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> wrists; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These tortoise-shell bracers fit so snuggly against their wearer's skin that they almost seem part of him. The wearer of these bracers becomes exceptionally calm and composed if she takes her time to accomplish particular tasks. Whenever she takes 20 on a skill check for a skill that primarily depends on her arms and hands, she gains a +5 competence bonus on the check.</p>
<h3 id="magic-wondrous-bracers_of_steadiness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aid">aid</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _bracers_of_sworn_vengeance = {title: "Bracers of Sworn Vengeance", jsx: <><h2 id="magic-wondrous-bracers_of_sworn_vengeance-bracers-of-sworn-vengeance">Bracers of Sworn Vengeance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 28</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 15th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These white leather bracers have delicate elven runes etched upon them, one reading "swift defeat" and the other "vengeance." Once per day, as an immediate action when the wearer takes hit point damage from a target, he may cry out, "Death to those who wrong me!", swearing vengeance against the attacker. The wearer gains a +1 competence bonus on weapon attack rolls made against the target of his sworn vengeance, and deals an additional 2d6 points of damage on successful weapon attack rolls.</p>
<p>For the duration of the effect, the wearer takes a -2 penalty on attack rolls against any target other than his sworn enemy. These bonuses and penalties last for 24 hours or until the sworn enemy is slain or destroyed by the wearer, whichever comes first. If the wearer fails to slay the target of his oath, these bracers cannot be used again until 7 days have passed.</p>
<h3 id="magic-wondrous-bracers_of_sworn_vengeance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shout">shout</Link>, creator must be an <Link to="/race/elf">elf</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _bracers_of_the_avenging_knight = {title: "Bracers of the Avenging Knight", jsx: <><h2 id="magic-wondrous-bracers_of_the_avenging_knight-bracers-of-the-avenging-knight">Bracers of the Avenging Knight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 11,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These silver bracers are polished to a mirrored sheen, but otherwise shift their appearance to match whatever suit of armor they are worn with.</p>
<p>If the wearer has levels in a class that grants a smite ability (such as a <Link to="/class/paladin">paladin</Link>, or a cleric with the <Link to="/domain/destruction">Destruction</Link> domain), her smite damage is treated as though she were a member of that class four levels higher. If the wearer is not a member of such a class, once per day she may make one smite attack, gaining a bonus on the attack roll equal to her Charisma bonus, and a +5 bonus to the damage roll on a hit.</p>
<h3 id="magic-wondrous-bracers_of_the_avenging_knight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless_weapon">bless weapon</Link>; <strong>Cost</strong> 5,750 gp</p>
</>};
const _bracers_of_the_glib_entertainer = {title: "Bracers of the Glib Entertainer", jsx: <><h2 id="magic-wondrous-bracers_of_the_glib_entertainer-bracers-of-the-glib-entertainer">Bracers of the Glib Entertainer</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 7,900 gp; <strong>Weight</strong> 1 lb.</p>
<p>These decorative bracers are stippled with vibrant colors and have various tiny bells sewn onto their surface. While wearing them, the wearer gains a +5 competence bonus on <Link to="/skill/perform">Perform</Link> checks. Once per day on command, the user can gain the benefit of the <em>glibness</em> spell.</p>
<h3 id="magic-wondrous-bracers_of_the_glib_entertainer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/glibness">glibness</Link>; <strong>Cost</strong> 3,950 gp</p>
</>};
const _bracers_of_the_merciful_knight = {title: "Bracers of the Merciful Knight", jsx: <><h2 id="magic-wondrous-bracers_of_the_merciful_knight-bracers-of-the-merciful-knight">Bracers of the Merciful Knight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 272</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 15,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>These golden bracers are engraved with images of celestial creatures. When worn by a <Link to="/class/paladin">paladin</Link>, he is considered four levels higher for the purposes of determining the uses per day and healing provided by his <Link to="/ability/lay_on_hands">lay on hands</Link> class feature. Additionally, once per day, the wearer can infuse a use of lay on hands with additional power, providing relief as a <em>lesser restoration</em> spell.</p>
<h3 id="magic-wondrous-bracers_of_the_merciful_knight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_serious_wounds">cure serious wounds</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Cost</strong> 7,800 gp</p>
</>};
const _bracers_of_the_shield_mates = {title: "Bracers of the Shield Mates", jsx: <><h2 id="magic-wondrous-bracers_of_the_shield_mates-bracers-of-the-shield-mates">Bracers of the Shield Mates</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 148</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These heavy, bronze bracers depict scenes of epic battle and heroic sacrifice. When worn together, they provide no benefit. When two individuals each wear a single bracer, each wearer gains a +2 shield bonus to AC as long as the two remain within 100 feet of each other.</p>
<p>By expending one use of mythic power as a swift action, the wearer of one of the bracers can teleport up to 100 feet per mythic tier to any unoccupied space adjacent to the other wearer. The wearer acts normally for the remainder of her turn, then immediately teleports back to her original space when her turn ends. Effects that prevent dimensional travel either from the wearer's space or to her destination block this ability.</p>
<h3 id="magic-wondrous-bracers_of_the_shield_mates-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _broken_rune_bracers_shoanti = {title: "Broken Rune Bracers (Shoanti)", jsx: <><h2 id="magic-wondrous-broken_rune_bracers_shoanti-broken-rune-bracers-shoanti">Broken Rune Bracers (Shoanti)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 229</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This pair of leather bracers is marked by runes of bondage from ancient days. Each rune is deliberately incomplete, in order to invert its intended function. Once per day, when a Shoanti wearer becomes possessed by <Link to="/spell/magic_jar">magic jar</Link>, <Link to="/spell/possession">possession</Link>, or a similar effect, the bracers automatically expel the possessing creature. The possessing creature does not have a chance to take any actions (such as removing the bracers) before this occurs.</p>
<h3 id="magic-wondrous-broken_rune_bracers_shoanti-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cast_out">cast out</Link>, creator must be a Shoanti; <strong>Cost</strong> 4,500 gp</p>
</>};
const _burglars_bracers = {title: "Burglar's Bracers", jsx: <><h2 id="magic-wondrous-burglars_bracers-burglars-bracers">Burglar's Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 1,050 gp; <strong>Weight</strong> 1 lb.</p>
<p>On command, these plain leather bracers can transform into a set of <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves' tools</Link>. They can transform back to their bracer form with another such command. Once per day, while using these thieves' tools or wearing these bracers, the user can take 10 on a single <Link to="/skill/disable_device">Disable Device</Link> check, even when in immediate danger or distracted.</p>
<h3 id="magic-wondrous-burglars_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 550 gp</p>
</>};
const _charm_bracelet = {title: "Charm Bracelet", jsx: <><h2 id="magic-wondrous-charm_bracelet-charm-bracelet">Charm Bracelet</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link><br/><strong>Aura</strong> faint varied; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>Tiny ornaments of gold hang from the links of a charm bracelet. In addition to 1d4+4 nonmagical charms, each bracelet carries one of each of the following magic charms. These magic charms can be activated with a command, producing the listed effect, but each charm can be only used once. After a charm is used, it dissolves into a thick vapor and dissipates.</p>
<blockquote>
<p><strong className="hl">Arming Sword:</strong> When detached, this charm transforms into a <Link to="/rule/masterwork_a">masterwork</Link> <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link> and a <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-weapon/longsword">longsword</Link>. They can either appear on the ground or within the hands of the creature that activated the charm, ready to use. These items last for 1 hour before turning into vapor.</p>
<p><strong className="hl">Healthy Apple:</strong> When detached, this charm becomes an apple that when eaten (a standard action that provokes attacks of opportunity) heals 2d8 hit points. In addition, if the creature eating the apple is afflicted with any poison or diseases, it can attempt a new saving throw against each such affliction. Each successful saving throw immediately ends the corresponding affliction.</p>
<p><strong className="hl">Loving Heart:</strong> Upon detaching this charm, the wearer can use <em>charm person</em> as a spell-like ability (as the spell, Will DC 11) any time before the end of her next turn.</p>
<p><strong className="hl">Lucky Star:</strong> When this charm is activated, it releases good luck in a 20-foot-radius <Link to="/misc/burst">burst</Link> centered on the wearer. The wearer and her allies within the burst gain a +2 luck bonus on ability checks, attack rolls, saving throws, and skill checks for 1 round.</p>
<p><strong className="hl">Peaceful Dove:</strong> Detaching this dove calms tempers within a 20-foot-radius burst centered on the wearer as though <em>calm emotions</em> (Will DC 13) had been cast. A creature affected by rage takes a -2 penalty on this saving throw.</p>
</blockquote>
<p>Reduce the price of a charm bracelet that has one or more expended charms by 1,580 gp per absent charm. The charm bracelet itself becomes a nonmagical bracelet worth 100 gp when the last charm is used, no matter the number of nonmagical charms left on the bracelet.</p>
<h3 id="magic-wondrous-charm_bracelet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/prayer">prayer</Link>, <Link to="/spell/shadow_weapon">shadow weapon</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _decorum_band = {title: "Decorum Band", jsx: <><h2 id="magic-wondrous-decorum_band-decorum-band">Decorum Band</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_goblins_1">Pathfinder Goblins #1 pg. 29</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This slim black leather bracer fits easily onto the wrist, growing tight against the skin within moments of putting it on. The wearer of a a decorum band is aware of any action that could cause a creature's <Link to="/skill/attitude">attitude</Link> toward the wearer to shift negatively. He acquires this information prior to performing such an action.</p>
<h3 id="magic-wondrous-decorum_band-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _dimensional_shackles = {title: "Dimensional Shackles", jsx: <><h2 id="magic-wondrous-dimensional_shackles-dimensional-shackles">Dimensional Shackles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 510</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 28,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>These shackles have magical runes traced across their <Link to="/eq-material/cold_iron">cold iron</Link> links. Any creature bound within them is affected as if a <em>dimensional anchor</em> spell were cast upon it (no save). They fit any Small to Large creature. The DC to break or slip out of the shackles is 30.</p>
<h3 id="magic-wondrous-dimensional_shackles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>; <strong>Cost</strong> 14,000 gp</p>
</>};
const _dueling_cuffs = {title: "Dueling Cuffs", jsx: <><h2 id="magic-wondrous-dueling_cuffs-dueling-cuffs">Dueling Cuffs</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 59</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These tight-fitting <Link to="/eq-material/mithral">mithral</Link> bracers are used throughout the Inner Sea region in nations where dueling is prominent. The wearer of dueling cuffs gains a +1 deflection bonus to AC. This bonus increases to +2 if the wearer is wielding one or more weapons that benefit from the <Link to="/feat/weapon_finesse">Weapon Finesse</Link> feat.</p>
<p>In a <Link to="/rule/duels">duel</Link>, the wielder doesn't take the normal -5 penalty when using the <Link to="/rule/dueling_parry">dueling parry</Link> action. In addition, the wielder can attempt to deflect ranged attacks from firearms with a dueling parry, but takes a -5 penalty on such attempts.</p>
<h3 id="magic-wondrous-dueling_cuffs-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bullet_shield">bullet shield</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _duelists_vambraces = {title: "Duelist's Vambraces", jsx: <><h2 id="magic-wondrous-duelists_vambraces-duelists-vambraces">Duelist's Vambraces</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Made from a mix of sturdy steel and boiled leather, these vambraces grant a +1 deflection bonus to AC while the wearer is wielding a <Link to="/misc/double">double</Link> weapon or two weapons (not including natural weapons or unarmed attacks). In addition, once per round, when attacking with an <Link to="/rule/off_hand">off-handed</Link> weapon, the wearer can reduce any penalties on attack rolls made with that weapon by 2.</p>
<h3 id="magic-wondrous-duelists_vambraces-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/shield">shield</Link>, creator must have the Two-Weapon fighting feat; <strong>Cost</strong> 4,000 gp</p>
</>};
const _electro_temporal_bracer = {title: "Electro-Temporal Bracer", jsx: <><h2 id="magic-wondrous-electro_temporal_bracer-electro-temporal-bracer">Electro-Temporal Bracer</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_122_into_the_shattered_continent">Pathfinder #122: Into the Shattered Continent pg. 74</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 32,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This rune-carved bracelet is made of thick, bright gold and allows the wearer to manipulate time through electricity magic. As a swift action, the wearer can activate the bracer, creating a nimbus of crackling blue energy that surrounds the hand wearing the electro-temporal bracer for up to 3 minutes each day. This duration need not be continuous, but it must be used in 1-minute increments. While the nimbus is active, spells with the electricity descriptor cast by the wearer have an additional effect, chosen by the wearer as each spell is cast: the spell <Link to="/misc/dazzle">dazzles</Link> all targets of the spell for 1 round, the spell <Link to="/misc/stagger">staggers</Link> a single target of the spell for 1 round, or the spell provides a single target of the spell the benefits of <em>haste</em> for 1 round. The staggered and <em>haste</em> effects affect only one target selected by the caster as the spell is cast, even if the spell affects multiple targets. There is no saving throw for these additional effects, but a target that avoids the effects of the electricity spell entirely (such as by negating the effect with a successful save, or by having immunity to the spell's damage) is not subject to the additional effect. (A target of an additional effect that successfully saves against the electricity spell but still takes partial damage is still subject to the additional effect.)</p>
<p>If the wearer takes at least 50 points of electricity damage from a single source (such as a trap or a spell), the wearer immediately benefits from the effects of <em>time stop,</em> and the electro-temporal bracer ceases functioning for 1 month.</p>
<h3 id="magic-wondrous-electro_temporal_bracer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/slow">slow</Link>, <Link to="/spell/time_stop">time stop</Link>; <strong>Cost</strong> 16,000 gp</p>
</>};
const _fate_woven_braid_of_the_norns = {title: "Fate-Woven Braid of the Norns", jsx: <><h2 id="magic-wondrous-fate_woven_braid_of_the_norns-fate-woven-braid-of-the-norns">Fate-Woven Braid of the Norns</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 54</Link><br/><strong>Aura</strong> strong abjuration and evocation; <strong>CL</strong> 16th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>At first glance, this circlet of plaited hair interwoven with a single gold thread appears to be nothing more than a personal memento or a lover's token. Closer examination reveals that each strand of hair seems to have neither a beginning nor an end. Most of these braids are blonde in color, but other hues are not unknown.</p>
<p>Up to three times per day, the wearer of a fate-woven braid of the norns can potentially negate a disastrous turn of fortune. Upon rolling a natural 1 on a saving throw or after failing a saving throw against a death effect, the wearer can activate the braid as a free action to reroll the saving throw.</p>
<p>The golden thread is vulnerable to severe twists of fate, though. If the result of any reroll obtained by the braid is ever a natural 20, the golden thread frays, permanently reducing the braid's daily reroll uses by one. If all three daily uses are eliminated in this manner, the golden thread snaps and the fate-woven braid of the norns falls apart into a nonmagical pile of wispy gray hair. A fate-woven braid of the norns uses up the entire wrist slot, even though the user wears only one at a time. The user can't use another item (even another fate-woven braid of the norns) that also uses the wrist slot.</p>
<h3 id="magic-wondrous-fate_woven_braid_of_the_norns-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_ward">death ward</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _harvesters_bindings = {title: "Harvester's Bindings", jsx: <><h2 id="magic-wondrous-harvesters_bindings-harvesters-bindings">Harvester's Bindings</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 31</Link><br/><strong>Aura</strong> faint abjurationa and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>These bronze bracers are etched with an elaborate crisscross pattern on their exterior and are lined with a set of six small barbs that are anchored into the interior. When worn, the bracers provide the wearer with a +2 circumstance bonus on Fortitude saves against poisons from venomous creatures. Anytime the wearer fails a saving throw against a poison from a venomous creature, he can say the bindings' command word as a standard action and cause the barbs in the bindings to pierce his skin and begin siphoning the poison from his body, preventing the poison from taking effect. After the poison has been siphoned off, the bracers glow faintly for 1 minute. While the bracers are glowing, the wearer can touch an empty vial to the bracers to deposit the stored venom into the vial. This extracted venom lasts up to 1 hour before becoming inert. The bindings cannot hold more than 1 dose of a poison from a venomous creature at a time. If the wearer attempts to siphon poison from himself while the bindings already hold a dose of poison, the stored poison immediately affects him and the other poison is instead siphoned and stored in the bindings.</p>
<h3 id="magic-wondrous-harvesters_bindings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/drain_poison">drain poison</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _high_elven_bracers = {title: "High Elven Bracers", jsx: <><h2 id="magic-wondrous-high_elven_bracers-high-elven-bracers">High Elven Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These finely crafted leather bracers have plates of silvered steel covering the back, and silver buckles at the wrist and forearm. The bracers enable the wearer to use any traditional elven weapon (<Link to="/eq-weapon/longbow">longbows</Link>, <Link to="/eq-weapon/composite_longbow">composite longbows</Link>, <Link to="/eq-weapon/longsword">longswords</Link>, <Link to="/eq-weapon/rapier">rapiers</Link>, <Link to="/eq-weapon/shortbow">shortbows</Link>, <Link to="/eq-weapon/composite_shortbow">composite shortbows</Link>, and any weapon with the word "elven" in its name) as if he were proficient in its use. If he uses such a weapon and is already proficient with it, he gains a +1 competence bonus on attack and damage rolls. Both bracers must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-high_elven_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, creator must be an <Link to="/race/elf">elf</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _howling_bracers = {title: "Howling Bracers", jsx: <><h2 id="magic-wondrous-howling_bracers-howling-bracers">Howling Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 230</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These bracers are made of heavy iron and have a pattern of howling wolves engraved upon them. Once per day on command, the wearer can clash the bracers together rhythmically. This causes the wolves etched into the bracers to come to life and let out a chorus of howls, with the effect of <em>crushing despair</em> (DC 16). Additionally, for every two creatures under the effect of the wearer's <Link to="/ability/raging_song">raging song</Link> when this ability is used, the DC increases by 1, up to a maximum increase of 5.</p>
<h3 id="magic-wondrous-howling_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/crushing_despair">crushing despair</Link>, creator must have the raging song class feature; <strong>Cost</strong> 3,500 gp</p>
</>};
const _inquisitors_bastion_vambraces = {title: "Inquisitor's Bastion Vambraces", jsx: <><h2 id="magic-wondrous-inquisitors_bastion_vambraces-inquisitors-bastion-vambraces">Inquisitor's Bastion Vambraces</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 273</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Constructed of blackened steel, these vambraces augment the protection granted to the <Link to="/class/inquisitor">inquisitor</Link> by the protection judgment. While under that judgment's effects, the inquisitor gains a sacred bonus both to CMD and on checks made to cast spells defensively. This bonus is equal to the sacred bonus the judgement grants to AC.</p>
<h3 id="magic-wondrous-inquisitors_bastion_vambraces-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must be an inquisitor with access to the protection judgment; <strong>Cost</strong> 2,000 gp</p>
</>};
const _ioun_spite_bracers = {title: "Ioun Spite Bracers", jsx: <><h2 id="magic-wondrous-ioun_spite_bracers-ioun-spite-bracers">Ioun Spite Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 36</Link>, <Link to="/source/agents_of_evil">Agents of Evil pg. 29</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These bracers find particular use by <Link to="/rule/aspis_consortium">Aspis</Link> agents who often tangle with the <Link to="/rule/pathfinder_society">Pathfinder Society</Link>. As a standard action, a creature wearing these bracers can attempt a <Link to="/rule/steal">steal</Link> combat maneuver check to nab any orbiting <Link to="/magic-wondrous/ioun_stone">ioun stone</Link> within 30 feet, though the ioun stone's owner receives a +4 circumstance bonus to her CMD. If the bracers' wearer succeeds, the stolen ioun stone embeds itself in one of the bracers' four available slots (each bracer has two). Embedded ioun stones provide their bonuses to the wearer and can be removed with a move action.</p>
<p>As a standard action, the wearer can temporarily drain the power of any ioun stone that is embedded in the bracers and isn't <Link to="/magic-ioun/dull_gray">dull gray</Link>, and can then channel that power to cast <em>magic missile</em> as a spell-like ability, firing three missiles at a target or targets up to 160 feet away. Drained ioun stones become dull gray for the next 2d4 hours.</p>
<h3 id="magic-wondrous-ioun_spite_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_missile">magic missile</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _lidless_charm_bracelet = {title: "Lidless Charm Bracelet", jsx: <><h2 id="magic-wondrous-lidless_charm_bracelet-lidless-charm-bracelet">Lidless Charm Bracelet</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_116_fangs_of_war">Pathfinder #116: Fangs of War pg. 46</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This bronze, serpentine bracelet has five dangling charms, each depicting an open and staring eye. Once per day as a standard action, the wearer can touch the bracelet to a creature with a <Link to="/umr/gaze">gaze</Link> attack (requiring a successful touch attack for unwilling creatures) and become immune to natural gaze attacks from all creatures of that kind for the following 24 hours. The wearer could, for example, touch the bracelet to a <Link to="/monster/basilisk">basilisk</Link> to gain immunity to the gaze attacks of all basilisks, but would not be immune to the gaze of a <Link to="/monster/medusa">medusa</Link>. This ability does not grant immunity to gaze attacks from spells or magic items such as <Link to="/magic-wondrous/eyes_of_doom">eyes of doom</Link>. For the duration of this immunity, the charms on the bracelet each appear to be closed eyes.</p>
<p>When the wearer fails a save against a gaze attack, she can expend a charm from the bracelet as an immediate action to reroll that saving throw, but must take the second result even if it is worse. An expended charm crumbles to dust. When the last charm is expended, the lidless charm bracelet loses all magical properties.</p>
<h3 id="magic-wondrous-lidless_charm_bracelet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>, <Link to="/spell/lock_gaze">lock gaze</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _longarm_bracers = {title: "Longarm Bracers", jsx: <><h2 id="magic-wondrous-longarm_bracers-longarm-bracers">Longarm Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>These bracers are constructed from woven strands of bamboo. Three times per day, as a swift action, the wearer can stretch her arms beyond their limits, increasing her reach by 5 feet until the start of her next turn. Her weapon attack rolls take a -4 penalty, while unarmed strikes and natural weapons using the arms take no penalty.</p>
<h3 id="magic-wondrous-longarm_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _lovers_bangle = {title: "Lover's Bangle", jsx: <><h2 id="magic-wondrous-lovers_bangle-lovers-bangle">Lover's Bangle</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_128_songbird_scion_saboteur">Pathfinder #128: Songbird, Scion, Saboteur pg. 36</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 750 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thick copper bracelet bears rows of lightly engraved hearts. Once per week, when the bracelet is worn and touched to another worn lover's bangle, the two become attuned and remain attuned until one of the bangles is removed or attuned to a different lover's bangle, or until a bangle's wearer is reduced below 0 hit points, is slain, or travels to a different plane. The wearer of the attuned lover's bangle immediately knows that the attunement has ended, but doesn't receive any indication about the event that broke the attunement.</p>
<h3 id="magic-wondrous-lovers_bangle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _manacles_of_cooperation = {title: "Manacles of Cooperation", jsx: <><h2 id="magic-wondrous-manacles_of_cooperation-manacles-of-cooperation">Manacles of Cooperation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 307</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> wrists; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These tight iron cuffs can fit over the wrists of any Large or smaller humanoid. When placed on a <Link to="/misc/helpless">helpless</Link> humanoid, they make the captive more docile and compliant. The prisoner never attempts to escape of its own volition and agrees to any reasonable request unless it succeeds at a DC 11 Will saving throw.</p>
<h3 id="magic-wondrous-manacles_of_cooperation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _merciful_vambraces = {title: "Merciful Vambraces", jsx: <><h2 id="magic-wondrous-merciful_vambraces-merciful-vambraces">Merciful Vambraces</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These vambraces are constructed of polished steel. When a <Link to="/class/paladin">paladin</Link> wears these vambraces, engravings of the holy symbol of a paladin's deity and other religious iconography mystically appear upon the metal's surface. Once per day, when the paladin uses her <Link to="/ability/lay_on_hands">lay on hands</Link> ability, she can choose to apply an additional mercy to that use of lay on hands that she did not already select. She must be of sufficient level to use that mercy.</p>
<h3 id="magic-wondrous-merciful_vambraces-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cleanse">cleanse</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _quickmetal_bracers_silver = {title: "Quickmetal Bracers (Silver)", jsx: <><h2 id="magic-wondrous-quickmetal_bracers_silver-quickmetal-bracers">Quickmetal Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 1,000 gp (Silver), 2,000 gp (Cold Iron), 5,000 gp (Adamantine); <strong>Weight</strong> 1 lb.</p>
<p>Once per day when a user wearing both these bracers speaks a command word, the metal turns entirely liquid and swims over the wearer's hands to cover her weapons. The user can cover a two-handed melee weapon or up to two one-handed or light melee weapons. For the next 10 rounds, the affected weapons can overcome damage reduction as though the weapons were made of adamantine, cold iron, or silver (as determined by the quickmetal bracers' type).</p>
<p>The heavy, shifting metal coating affects the balance of manufactured weapons, imposing a -2 penalty on attack rolls. <Link to="/misc/improvised_weapons">Improvised weapons</Link>, however, are already unwieldy, and the metal coating doesn't significantly affect their balance. If the wielder lets go of a weapon affected by the bracers, the liquid metal immediately turns back into a solid metal bracer - or bracers, in the case of a two-handed weapon - reappearing on the user's wrists. The bracers cannot therefore affect thrown weapons or ranged weapon ammunition.</p>
<h3 id="magic-wondrous-quickmetal_bracers_silver-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/major_creation">major creation</Link>; <strong>Cost</strong> 500 gp (Silver), 1,000 gp (Cold Iron), 2,500 gp (Adamantine)</p>
</>};
const _rift_rending_bracers = {title: "Rift-Rending Bracers", jsx: <><h2 id="magic-wondrous-rift_rending_bracers-rift-rending-bracers">Rift-Rending Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 9</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When worn by a <Link to="/class/kineticist">kineticist</Link>, these bracers develop finely inscribed patterns on their once-plain surfaces that reflect the wearer's elemental connection. As a full-round action, a kineticist wearing the bracers can accept 3 points of burn to tear open a brief rift between her current location and the Material Plane, Ethereal Plane, or an Elemental Plane; this behaves as per <em>plane shift,</em> but the rift is able to transport only her. By accepting an additional point of burn, she can allow up to 8 willing creatures to travel with her. When traveling to or from the plane that corresponds to her elemental focus, the total burn cost required to activate the bracers is reduced by 1.</p>
<p>Rift-rending bracers must be worn for 24 hours before a kineticist can activate them.</p>
<h3 id="magic-wondrous-rift_rending_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _saints_protection_charm = {title: "Saint's Protection Charm", jsx: <><h2 id="magic-wondrous-saints_protection_charm-saints-protection-charm">Saint's Protection Charm</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 11</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> -</p>
<p>A copper disc attached to this bracelet bears the image of a figure in religious garb. The wearer gains a +1 deflection bonus to AC and a +1 resistance bonus on saves. These bonuses apply only against attacks made or effects created by extraplanar creatures.</p>
<h3 id="magic-wondrous-saints_protection_charm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/protection_from_chaos_evil_good_law">protection from chaos, evil, good, or law</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _scattershot_bracers = {title: "Scattershot Bracers", jsx: <><h2 id="magic-wondrous-scattershot_bracers-scattershot-bracers">Scattershot Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 351</Link></p>
<p><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Weight</strong> 1 lb.</p>
<p>These wristbands appear to be bracers of archery until they are worn. The wearer takes a -2 penalty on all ranged attack rolls. A successful <Link to="/spell/remove_curse">remove curse</Link> spell is required before these bracers can be removed.</p>
<h3 id="magic-wondrous-scattershot_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/bracers_of_archery_greater">bracers of archery</Link>, either greater or lesser; <strong>Cost</strong> -</p>
</>};
const _seafaring_stanchions = {title: "Seafaring Stanchions", jsx: <><h2 id="magic-wondrous-seafaring_stanchions-seafaring-stanchions">Seafaring Stanchions</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 63</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These unmarked bracers of oxidized steel slip easily onto the wrists. As a swift action while submerged underwater, the wearer can tap the bracers together, causing the bracers and any armor he wears to immediately be removed. Removed armor is disassembled, becomes incredibly buoyant, and floats to the surface. After 4 hours, if the items are still in the water, they lose their buoyancy and sink.</p>
<h3 id="magic-wondrous-seafaring_stanchions-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 2,400 gp</p>
</>};
const _seducers_bane = {title: "Seducer's Bane", jsx: <><h2 id="magic-wondrous-seducers_bane-seducers-bane">Seducer's Bane</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 9,900 gp; <strong>Weight</strong> -</p>
<p>This slender silver bracelet is worked in an intertwined design of three flowers. A DC 20 <Link to="/skill/knowledge_nature">Knowledge (nature)</Link> check identifies the flowers as acacia, apocynum, and bilberry, symbolizing concealment, treachery, and falsehood.</p>
<p>The bracelet grants the wearer a +5 competence bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks, and a +5 resistance bonus on Will saves against enchantment effects. If the wearer makes a successful Will save against an enchantment, the caster of that spell incorrectly senses the effect has succeeded. Additionally, the bracelet's wearer knows an enchantment targeted him and the enchantment's source. Seducer's bane creates an aura on its wearer, visible to <em>detect magic,</em> matching the failed enchantment spell or effect, and lasting as long as the intended enchantment's duration. However, if the bracelet's wearer attacks the caster or its allies, or otherwise acts in a way that's contradictory to the failed spell's effect, the caster of that spell immediately realizes the enchantment was ineffective.</p>
<h3 id="magic-wondrous-seducers_bane-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/resistance">resistance</Link>, creator must have 3 ranks in Sense Motive; <strong>Cost</strong> 4,950 gp</p>
</>};
const _shackles_of_compliance = {title: "Shackles of Compliance", jsx: <><h2 id="magic-wondrous-shackles_of_compliance-shackles-of-compliance">Shackles of Compliance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link>, <Link to="/source/pathfinder_55_the_wormwood_mutiny">Pathfinder #55: The Wormwood Mutiny pg. 58</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> wrists; <strong>Price</strong> 3,280 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These battered iron manacles are typically found with a small spiked iron key in one of the locks. The shackles magically adjust themselves to fit around the wrists of any creature from Small to Large size and automatically lock. A creature wearing shackles of compliance becomes more susceptible to intimidation. Any creature attempting to intimidate or demoralize a target wearing shackles of compliance gains a +4 bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. In addition, the holder of the manacles' key can cast <em>command</em> (DC 25 Will) on the wearer of the shackles three times per day.</p>
<p>Shackles of compliance have hardness 10 and 10 hit points, and a DC 30 <Link to="/skill/disable_device">Disable Device</Link> check is required to pick the shackles' lock. A manacled creature can break free with a DC 28 Strength check or DC 35 <Link to="/skill/escape_artist">Escape Artist</Link> check. The manacles lock can be opened with a DC 30 Disable Device check.</p>
<h3 id="magic-wondrous-shackles_of_compliance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/command">command</Link>; <strong>Cost</strong> 1,930 gp</p>
</>};
const _shackles_of_durance_vile = {title: "Shackles of Durance Vile", jsx: <><h2 id="magic-wondrous-shackles_of_durance_vile-shackles-of-durance-vile">Shackles of Durance Vile</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 274</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 125</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 16,200 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These masterwork iron manacles sap the will of their wearer. When they are attached to a humanoid creature as their command word is spoken, they affect their prisoner with a <em>dominate person</em> spell, except that if the prisoner fails its saving throw, the effect lasts for as long as the shackles are attached. Removing or destroying the shackles immediately breaks the enchantment. The shackles can be so used once per day. Shackles of durance vile can only be activated against a <Link to="/misc/helpless">helpless</Link>, restrained, or willing creature; if attached to a creature still able to resist they function only as <Link to="/eq-misc/manacles_mwk">manacles</Link>, albeit superior ones. Shackles of durance vile have hardness 15, 20 hit points, and a <Link to="/eq-misc/superior_lock">superior lock</Link>. They have a break DC of 30 and an <Link to="/skill/escape_artist">Escape Artist</Link> DC of 35.</p>
<h3 id="magic-wondrous-shackles_of_durance_vile-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dominate_person">dominate person</Link>; <strong>Cost</strong> 8,200 gp</p>
</>};
const _silver_smite_bracelet = {title: "Silver Smite Bracelet", jsx: <><h2 id="magic-wondrous-silver_smite_bracelet-silver-smite-bracelet">Silver Smite Bracelet</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This heavy silver bracelet is etched with icons of purity, fidelity, chastity, and honor, and glows with a soft white light whenever its owner prays. The wearer of this bracelet treats her <Link to="/class/paladin">paladin</Link> level as 4 higher than normal for the purpose of her smite evil class feature.</p>
<h3 id="magic-wondrous-silver_smite_bracelet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/align_weapon">align weapon</Link>, creator must be a paladin; <strong>Cost</strong> 8,000 gp</p>
</>};
const _sleeves_of_many_garments = {title: "Sleeves of Many Garments", jsx: <><h2 id="magic-wondrous-sleeves_of_many_garments-sleeves-of-many-garments">Sleeves of Many Garments</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 1st<br/><strong>Slot</strong> wrists; <strong>Price</strong> 200 gp; <strong>Weight</strong> 1 lb.</p>
<p>These translucent cloth tubes easily fit over their wearer's arms. The wearer of these sleeves can, when she slips them on, choose to transform the appearance of her current garments into any other nonmagical set of clothing. These new clothes fit her perfectly and are always clean and mended unless she specifically designates otherwise. When she removes the sleeves, her clothes revert to their original form.</p>
<h3 id="magic-wondrous-sleeves_of_many_garments-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Cost</strong> 100 gp</p>
</>};
const _spellguard_bracers = {title: "Spellguard Bracers", jsx: <><h2 id="magic-wondrous-spellguard_bracers-spellguard-bracers">Spellguard Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 4th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Typically made of leather dyed blue and decorated with star-shaped studs, these bracers are used by spellcasters who practice their art in the heat of combat. The bracers grant the wearer a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks made to cast defensively. Three times per day, the wearer can choose to roll a concentration check to cast defensively twice and take the better result.</p>
<h3 id="magic-wondrous-spellguard_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/combat_casting">Combat Casting</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/warding_weapon">warding weapon</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _spellsight_bracer = {title: "Spellsight Bracer", jsx: <><h2 id="magic-wondrous-spellsight_bracer-spellsight-bracer">Spellsight Bracer</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 269</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 60</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 2,100 gp; <strong>Weight</strong> 1 lb.</p>
<p>Dozens of variants of this bracer exist, but they are usually leather, always ornately patterned, and bear a single spherical polished stone or gem (typically a carbuncle, olivine, or sard) mounted near the wrist. Medium to high-ranking <Link to="/faith/nethys">Nethysian</Link> priests and priestesses often wear spellsight bracers, which also serve as a quick means of identifying fellow followers of the All-Seeing Eye. The wearer can use <em>detect magic</em> once per day. When she does, the spherical stone or gem in the bracer appears to open like a human eye. The bracer also provides a +1 resistance bonus on Will saving throws. A spellsight bracer uses up the wearer's entire wrist slot; the wearer may not use another item (even another spellsight bracer) that also uses the wrist slot, though a matching nonmagical bracer is often worn on the other wrist.</p>
<p>If Nethys is the wearer's patron, the wearer can use the bracer as if it were a <Link to="/magic-rod/lesser_silent_metamagic_rod">lesser silent metamagic rod</Link> once per day. The wearer can spontaneously convert prepared spells or use available spell slots to cast <em>mage hand,</em> even if this spell is not on the wearer's class spell list or the wearer does not know the spell. Using either of these abilities also causes the eye in the bracer to open.</p>
<h3 id="magic-wondrous-spellsight_bracer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/silent_spell">Silent Spell</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 1,050 gp</p>
</>};
const _style_stealing_vambrace = {title: "Style-Stealing Vambrace", jsx: <><h2 id="magic-wondrous-style_stealing_vambrace-style-stealing-vambrace">Style-Stealing Vambrace</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 17</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This plain silver-and-steel bracelet grants the <Link to="/magic-enh/keen">keen</Link> weapon special ability to any piercing or slashing weapon wielded by the wearer. Each time the wearer confirms a critical hit with such a weapon, however, she must succeed at a DC 17 Fortitude save or the bracelet severs her hand, dealing 1d6 points of <Link to="/rule/dexterity_drain">Dexterity drain</Link> and 2d6 points of <Link to="/rule/bleed">bleed</Link> damage. The style-stealing vambrace and the severed hand immediately teleport to the item's creator if he is on the same plane, or else drop to the ground if he is not.</p>
<p>Once per day, a creature holding the severed hand can speak the bracelet's command word to gain access to one <Link to="/main/combat_feat">combat feat</Link> known by the previous wearer for 24 hours, as if it were a bonus feat. The creature must meet all of the usual prerequisites for the feat.</p>
<p>The wearer's hand can be restored instantly with a <Link to="/spell/regenerate">regenerate</Link> spell, or with a <Link to="/spell/restoration">restoration</Link> spell or <Link to="/umr/regeneration">regeneration</Link> (such as that granted by a <Link to="/magic-ring/ring_of_regeneration">ring of regeneration</Link>) if the severed hand is held against the stump. Restoring the wearer's hand removes the Dexterity drain. The style-stealing vambrace cannot be removed from the severed hand it holds or be reused until its victim dies or the hand is reattached.</p>
<h3 id="magic-wondrous-style_stealing_vambrace-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/gentle_repose">gentle repose</Link>, <Link to="/spell/keen_edge">keen edge</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _swallowtail_bracers = {title: "Swallowtail Bracers", jsx: <><h2 id="magic-wondrous-swallowtail_bracers-swallowtail-bracers">Swallowtail Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_75_demons_heresy">Pathfinder #75: Demon's Heresy pg. 63</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These delicate sliver bracers are decorated with blue butterflies. While worn, swallowtail bracers grant the wearer a +1 luck bonus on all saving throws, ability checks, and skill checks. If the wearer worships <Link to="/faith/desna">Desna</Link>, the bracers grant an additional boon: Once per day, by speaking a command word and the name and/or title of the intended recipient, the wearer may cast <em>dream.</em> Such a wearer is also immune to <Link to="/spell/nightmare">nightmare</Link>, and when the wearer is targeted by that spell, the effects reflect back upon the caster.</p>
<h3 id="magic-wondrous-swallowtail_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/dream">dream</Link>, creator must worship <Link to="/faith/desna">Desna</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _thorned_manacles = {title: "Thorned Manacles", jsx: <><h2 id="magic-wondrous-thorned_manacles-thorned-manacles">Thorned Manacles</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 35,600 gp; <strong>Weight</strong> 2 lbs.</p>
<p>When placed on a <Link to="/misc/helpless">helpless</Link>, two-armed creature of size Tiny to Huge, these barbed manacles transform to match the creature's size and prevent the captive from utilizing any extradimensional magic, as <em>dimensional anchor</em> (no save). Removing the manacles - whether as an escape attempt or by the owner - requires a successful DC 30 Strength check or a successful DC 37 <Link to="/skill/escape_artist">Escape Artist</Link> check; regardless of whether such an attempt succeeds, the manacles deal 2d6+7 points of piercing damage to the victim. The manacles have hardness 12 and 20 hit points.</p>
<h3 id="magic-wondrous-thorned_manacles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>, <Link to="/spell/thorn_body">thorn body</Link>; <strong>Cost</strong> 17,800 gp</p>
</>};
const _vambraces_of_defense = {title: "Vambraces of Defense", jsx: <><h2 id="magic-wondrous-vambraces_of_defense-vambraces-of-defense">Vambraces of Defense</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These polished steel vambraces grant a +1 deflection bonus to AC. Once per day, as an immediate action, if the wearer has at least one hand free, when he would normally be hit with an attack from a ranged weapon, he may deflect it with the bracers, taking no damage from it, as if he had the <Link to="/feat/deflect_arrows">Deflect Arrows</Link> feat.</p>
<h3 id="magic-wondrous-vambraces_of_defense-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _vambraces_of_the_genie = {title: "Vambraces of the Genie (Efreeti)", jsx: <><h2 id="magic-wondrous-vambraces_of_the_genie-vambraces-of-the-genie">Vambraces of the Genie</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 14,400 gp (Efreeti), 18,900 gp (Djinni), 18,900 gp (Marid), 18,900 gp (Shaitan); <strong>Weight</strong> 3 lbs.</p>
<p>These bracers are decorated with icons representing air, earth, fire, or water, and depictions of genies appropriate to that element. The item protects the wearer against hot and cold environments as if she were using endure elements The vambraces' materials and other powers depend on their associated genie type.</p>
<blockquote>
<p><em>Djinni:</em> These <Link to="/eq-material/mithral">mithral</Link> bracers allow the wearer to use <Link to="/spell/gaseous_form">gaseous form</Link>, <Link to="/spell/invisibility">invisibility</Link>, and <Link to="/spell/wind_wall">wind wall</Link> each once per day.</p>
<p><em>Efreeti:</em> These scorched bronze bracers allow the wearer to use <em>invisibility</em> (self only), <Link to="/spell/produce_flame">produce flame</Link>, and <Link to="/spell/pyrotechnics">pyrotechnics</Link> each once per day.</p>
<p><em>Marid:</em> These coral bracers allow the wearer to use <Link to="/spell/hydraulic_torrent">hydraulic torrent</Link>, <em>invisibility,</em> and <Link to="/spell/water_breathing">water breathing</Link> each once per day.</p>
<p><em>Shaitan:</em> These <Link to="/eq-material/adamantine">adamantine</Link> bracers allow the wearer to use <Link to="/spell/glitterdust">glitterdust</Link>, <Link to="/spell/meld_into_stone">meld into stone</Link>, and <Link to="/spell/stone_shape">stone shape</Link> each once per day.</p>
</blockquote>
<h3 id="magic-wondrous-vambraces_of_the_genie-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, and the three spells the wearer can use; <strong>Cost</strong> 7,200 gp (Efreeti), 9,450 gp (Djinni), 9,450 gp (Marid), 9,450 gp (Shaitan)</p>
</>};
const _vambraces_of_the_tactician = {title: "Vambraces of the Tactician", jsx: <><h2 id="magic-wondrous-vambraces_of_the_tactician-vambraces-of-the-tactician">Vambraces of the Tactician</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These vambraces change their appearance depending on who wears them. If the wearer is a <Link to="/class/cavalier">cavalier</Link>, these vambraces display the symbol of his order. When unworn or in the hands of a non-cavalier, they appear to be an ordinary pair of steel vambraces. A cavalier wearing these vambraces is considered two class levels higher for purposes of determining the effects of his challenge class feature. Furthermore, once per day as a swift action, a cavalier with the tactician class feature can increase the area in which he grants teamwork feats. Before the end of his next turn, when the cavalier grants his allies a teamwork feat, he can grant it to all allies within 60 feet, though they must still be able to see and hear him.</p>
<h3 id="magic-wondrous-vambraces_of_the_tactician-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _vanishing_sheath = {title: "Vanishing Sheath", jsx: <><h2 id="magic-wondrous-vanishing_sheath-vanishing-sheath">Vanishing Sheath</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 237</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This small sheath attaches to the wrist with a leather strap. The sheath can accommodate any single light weapon, wand, or piece of ammunition weighing no more than 5 pounds. While sheathed, the weapon is hidden in an extradimensional space and is weightless. As a swift action, the wearer can flex her wrist, ejecting the weapon into her hand. If her hand is not empty, the weapon remains sheathed. Stowing a weapon in the sheath requires a move action. The wearer gains a +4 bonus on any <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> check to oppose the <Link to="/skill/perception">Perception</Link> check of someone observing or frisking the wearer in search of a weapon in the sheath.</p>
<p>Vanishing sheaths can be worn in pairs - one on each arm. A person wearing two vanishing sheaths can eject either or both weapons with a single swift action.</p>
<h3 id="magic-wondrous-vanishing_sheath-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _verdant_vine = {title: "Verdant Vine", jsx: <><h2 id="magic-wondrous-verdant_vine-verdant-vine">Verdant Vine</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 275</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> wrists; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>Consisting of a vine with five green berries, a verdant vine is worn tied around the wrist. Once per day on command, the wearer can pinch a berry off the vine, and throw it up to 30 feet away, like a <Link to="/rule/throw_splash_weapon">splash weapon</Link>. Viciously thorny vines erupt in a 20-foot radius from the point of impact, even if the berry misses its target. Creatures within the area must succeed at a DC 16 Reflex saving throw or become <Link to="/rule/entangled">entangled</Link>, as the spell <em>entangle,</em> as the vines coil around the creature's legs. The vines persist, but at the start of the affected creature's turn, it gains a new saving throw against the effect. If the affected creature fails the saving throw, it also takes 1d4 points of damage.</p>
<p>A DC 20 Strength check, made as a standard action, allows an affected creature to break free and end the effect. Failing the check causes the vines to constrict, dealing 1d4 points of damage.</p>
<h3 id="magic-wondrous-verdant_vine-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/entangle">entangle</Link>, <Link to="/spell/plant_growth">plant growth</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
